  for r in select * from (values
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „სასამართლო ხელისუფლება“?', 'easy', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 1 ადგენს, რომ სასამართლო ხელისუფლება დამოუკიდებელია სახელმწიფო ხელისუფლების სხვა შტოებისაგან და მას ახორციელებენ მხოლოდ სასამართლოები.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 1', '', '2026-03-04', false, 'სასამართლო ხელისუფლება დამოუკიდებელია სახელმწიფო ხელისუფლების სხვა შტოებისაგან და მას ახორციელებენ მხოლოდ სასამართლოები.', 'სააპელაციო სასამართლოს მოსამართლეთა რაოდენობას განსაზღვრავს საქართველოს იუსტიციის უმაღლესი საბჭო.', 'საჩივარი ზეპირი მოსმენით განიხილება უზენაესი სასამართლოს საკვალიფიკაციო პალატის ღია სხდომაზე.', 'მართლმსაჯულების დაუბრკოლებლად განხორციელების, სასამართლო პრაქტიკის შესწავლისა და განზოგადების, სასამართლო სტატისტიკის ანალიზის, აგრეთვე სასამართლოს სხვა საქმიანობის უზრუნველყოფის მიზნით საქართველოს საერთო სასამართლოებში მოქმედებენ სასამართლოთა აპარატები.', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „ტერმინთა განმარტება“?', 'medium', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 1¹ ადგენს, რომ ამ კანონის XII​1 თავში გამოყენებულ ტერმინებს აქვს შემდეგი მნიშვნელობა:', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 1¹', '', '2026-03-04', false, 'სააპელაციო სასამართლო საპროცესო კანონით დადგენილი წესით, კოლეგიურად, 3 მოსამართლის შემადგენლობით განიხილავს სააპელაციო საჩივრებს რაიონული (საქალაქო) სასამართლოების გადაწყვეტილებებზე.', 'ამ კანონის XII​1 თავში გამოყენებულ ტერმინებს აქვს შემდეგი მნიშვნელობა:', 'მოსამართლის თანამდებობაზე უვადოდ გამწესებაზე უარის თქმის შესახებ საქართველოს იუსტიციის უმაღლესი საბჭოს განმეორებითი გადაწყვეტილება საჩივრდება მოსამართლის თანამდებობაზე უვადოდ გამწესებაზე უარის თქმის შესახებ საქართველოს იუსტიციის უმაღლესი საბჭოს გადაწყვეტილების გასაჩივრებისათვის ამ კანონით დადგენილი წესით.', 'ანაზღაურებადი სტაჟირებისას პირი ინიშნება სასამართლოს აპარატის შესაბამის თანამდებობაზე.', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „საქართველოს საერთო სასამართლოების სისტემა“?', 'medium', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 2 ადგენს, რომ საქართველოს საერთო სასამართლოებია: რაიონული (საქალაქო) სასამართლო, სააპელაციო სასამართლო, საქართველოს უზენაესი სასამართლო.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 2', '', '2026-03-04', false, 'სააპელაციო სასამართლოს თავმჯდომარე:', 'შემფასებლის საქმიანობაში უკანონო ჩარევა დაუშვებელია და იწვევს საქართველოს სისხლის სამართლის კოდექსით გათვალისწინებულ პასუხისმგებლობას.', 'საქართველოს საერთო სასამართლოებია: რაიონული (საქალაქო) სასამართლო, სააპელაციო სასამართლო, საქართველოს უზენაესი სასამართლო.', 'სასამართლოში საქმეები იხილება სასამართლო სხდომის მდივნის მონაწილეობით.', 'C'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „უფლების სასამართლო წესით დაცვა“?', 'medium', 'სწორი პასუხია D, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 3 ადგენს, რომ ყოველ ადამიანს აქვს უფლება, თავის უფლებათა და თავისუფლებათა დასაცავად პირადად ან წარმომადგენლის მეშვეობით პირდაპირ მიმართოს სასამართლოს.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 3', '', '2026-03-04', false, 'სააპელაციო სასამართლოს თავმჯდომარის პირველი მოადგილე:', 'ვაკანსიის წარმოშობის შემთხვევაში შესაძლებელია თანამდებობაზე დანიშნული მოსამართლე მისივე თანხმობით კონკურსის გარეშე დაინიშნოს რაიონული (საქალაქო) ან სააპელაციო სასამართლოს მოსამართლედ.', 'რაიონულ (საქალაქო), სააპელაციო და უზენაეს სასამართლოებში მოსამართლეთა შორის საქმეები ნაწილდება ავტომატურად, ელექტრონული სისტემის მეშვეობით, შემთხვევითი განაწილების პრინციპის დაცვით.', 'ყოველ ადამიანს აქვს უფლება, თავის უფლებათა და თავისუფლებათა დასაცავად პირადად ან წარმომადგენლის მეშვეობით პირდაპირ მიმართოს სასამართლოს.', 'D'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „სასამართლო გადაწყვეტილებათა სავალდებულოობა“?', 'hard', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 4 ადგენს, რომ სასამართლოს აქტი, აგრეთვე თავისი უფლებამოსილების განსახორციელებლად სასამართლოს მოთხოვნა და განკარგულება სავალდებულოა საქართველოს მთელ ტერიტორიაზე ყველა ფიზიკური და იურიდიული პირისათვის, სახელმწიფო და მუნიციპალიტეტის ორგანოსათვის.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 4', '', '2026-03-04', false, 'სასამართლოს აქტი, აგრეთვე თავისი უფლებამოსილების განსახორციელებლად სასამართლოს მოთხოვნა და განკარგულება სავალდებულოა საქართველოს მთელ ტერიტორიაზე ყველა ფიზიკური და იურიდიული პირისათვის, სახელმწიფო და მუნიციპალიტეტის ორგანოსათვის.', 'რაიონული (საქალაქო) სასამართლო იქმნება და მისი სამოქმედო ტერიტორია განისაზღვრება საქართველოს იუსტიციის უმაღლესი საბჭოს გადაწყვეტილებით.', 'ამასთანავე, ეს წესი არ გამოიყენება იმ შემთხვევაში, თუ მოსამართლე თავისი ინიციატივით მიმართავს საქართველოს იუსტიციის უმაღლეს საბჭოს მისი სხვა სასამართლოში მივლინების თაობაზე.', 'სასამართლოების მანდატურის სამსახურების საქმიანობის საერთო ხელმძღვანელობასა და კონტროლს ახორციელებს საქართველოს იუსტიციის უმაღლესი საბჭოს შესაბამისი სტრუქტურული ერთეული.', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მართლმსაჯულებისა და სამართალწარმოების პრინციპები“?', 'hard', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 6 ადგენს, რომ მართლმსაჯულება ხორციელდება კანონისა და სასამართლოს წინაშე საქმეში მონაწილე ყველა პირის თანასწორობის საფუძველზე, აგრეთვე საქვეყნოობის, მოსამართლეთა შეუცვლელობისა და დამოუკიდებლობის პრინციპების დაცვით.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 6', '', '2026-03-04', false, 'რაიონული (საქალაქო) სასამართლო შედგება არანაკლებ 2 მოსამართლისაგან.', 'მართლმსაჯულება ხორციელდება კანონისა და სასამართლოს წინაშე საქმეში მონაწილე ყველა პირის თანასწორობის საფუძველზე, აგრეთვე საქვეყნოობის, მოსამართლეთა შეუცვლელობისა და დამოუკიდებლობის პრინციპების დაცვით.', 'უზენაესი სასამართლოს თავმჯდომარე და უზენაესი სასამართლოს წევრები ფიცს დებენ საქართველოს პარლამენტის წინაშე, ხოლო სააპელაციო და რაიონული (საქალაქო) სასამართლოების მოსამართლეები – საქართველოს იუსტიციის უმაღლესი საბჭოს წინაშე.', 'სასამართლოს მანდატურის სამსახურის უფროსს თანამდებობაზე ნიშნავს და თანამდებობიდან ათავისუფლებს შესაბამისად სასამართლოს თავმჯდომარე ან საქართველოს იუსტიციის უმაღლესი საბჭოს მდივანი.', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლის დამოუკიდებლობა“?', 'easy', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 7 ადგენს, რომ მოსამართლე თავის საქმიანობაში დამოუკიდებელია.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 7', '', '2026-03-04', false, 'რაიონული (საქალაქო) სასამართლო არის პირველი ინსტანციის სასამართლო, რომელიც მისი განსჯადობისთვის მიკუთვნებულ საქმეს საქართველოს საპროცესო კანონმდებლობით დადგენილი წესით განიხილავს ერთპიროვნულად ან, კანონით გათვალისწინებულ შემთხვევაში, – კოლეგიურად, 3 მოსამართლის შემადგენლობით.', 'მოსამართლის თანამდებობა შეუთავსებელია ნებისმიერ სხვა თანამდებობასთან და ანაზღაურებად საქმიანობასთან, გარდა საქართველოს კონსტიტუციით დადგენილი გამონაკლისისა.', 'მოსამართლე თავის საქმიანობაში დამოუკიდებელია.', 'უზრუნველყოფს მოსამართლეების, სასამართლო პროცესის მონაწილეებისა და მოწმეების უსაფრთხოებას;', 'C'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „სასამართლოს საქმიანობაში ჩარევის დაუშვებლობა“?', 'hard', 'სწორი პასუხია D, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 8 ადგენს, რომ სახელმწიფო თუ მუნიციპალიტეტის ორგანოს, დაწესებულებას, საზოგადოებრივ თუ პოლიტიკურ გაერთიანებას, თანამდებობის პირს, იურიდიულ პირს თუ ფიზიკურ პირს ეკრძალებათ ნებისმიერი ფორმით სასამართლოს დამოუკიდებლობის შელახვა.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 8', '', '2026-03-04', false, 'რაიონულ (საქალაქო) სასამართლოში, სადაც ორი მოსამართლეა, ერთი განიხილავს სისხლის სამართლის საქმეებს, ხოლო მეორე – სამოქალაქო და სხვა კატეგორიის საქმეებს, გარდა საქართველოს საპროცესო კანონმდებლობით დადგენილი შემთხვევებისა.', 'დაუშვებელია მისი სისხლის სამართლის პასუხისგებაში მიცემა, დაკავება ან დაპატიმრება, საცხოვრებელი ან სამუშაო ადგილის, მანქანის ან პირადი გაჩხრეკა საქართველოს იუსტიციის უმაღლესი საბჭოს თანხმობის გარეშე.', 'სასამართლოს მანდატურს ფიზიკური ძალის, სპეციალური საშუალებებისა და იარაღის გამოყენების უფლება აქვს მხოლოდ იმ შემთხვევაში, როდესაც სხვა, შედარებით მსუბუქი ზომების გამოყენებით შეუძლებელია მისი სამსახურებრივი მოვალეობების შესრულება.', 'სახელმწიფო თუ მუნიციპალიტეტის ორგანოს, დაწესებულებას, საზოგადოებრივ თუ პოლიტიკურ გაერთიანებას, თანამდებობის პირს, იურიდიულ პირს თუ ფიზიკურ პირს ეკრძალებათ ნებისმიერი ფორმით სასამართლოს დამოუკიდებლობის შელახვა.', 'D'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „სამართალწარმოების ენა“?', 'medium', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 10 ადგენს, რომ სამართალწარმოება ხორციელდება სახელმწიფო ენაზე.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 10', '', '2026-03-04', false, 'სამართალწარმოება ხორციელდება სახელმწიფო ენაზე.', 'რაიონული (საქალაქო) სასამართლოს განსჯადობა, ასევე მაგისტრატი მოსამართლის განსჯადობა განისაზღვრება კანონით.', 'რაიონული (საქალაქო) სასამართლოს მოსამართლე შეიძლება დაინიშნოს სააპელაციო სასამართლოში, თუ იგი რაიონულ (საქალაქო) სასამართლოში მოსამართლის უფლებამოსილებას ახორციელებდა არანაკლებ 3 წლის განმავლობაში.', 'საქართველოს მოსამართლეთა კონფერენცია არის საქართველოს საერთო სასამართლოების მოსამართლეთა თვითმმართველობის ორგანო.', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „გადაწყვეტილების მიღება“?', 'medium', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 11 ადგენს, რომ მოსამართლე გადაწყვეტილებას იღებს ერთპიროვნულად, ხოლო მოსამართლეები – კოლეგიურად.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 11', '', '2026-03-04', false, 'რაიონული (საქალაქო) სასამართლოს თავმჯდომარეს შესაბამისი სასამართლოს მოსამართლეთაგან, ხოლო იმ სასამართლოს თავმჯდომარეს, სადაც შექმნილია სასამართლო კოლეგიები, – მათ შორის, სასამართლო კოლეგიების თავმჯდომარეთაგან, 10 წლის ვადით თანამდებობაზე ნიშნავს საქართველოს იუსტიციის უმაღლესი საბჭო დასაბუთებული გადაწყვეტილებით.', 'მოსამართლე გადაწყვეტილებას იღებს ერთპიროვნულად, ხოლო მოსამართლეები – კოლეგიურად.', 'უზენაესი სასამართლოს თავმჯდომარისა და უზენაესი სასამართლოს მოსამართლის თანამდებობიდან გადაყენება შეიძლება მხოლოდ იმპიჩმენტის წესით.', 'საქართველოს მოსამართლეთა კონფერენციის სისტემაში, ამ კანონის 63-ე მუხლით განსაზღვრული ფუნქციების შესრულების ხელშეწყობის მიზნით, იქმნება ადმინისტრაციული კომიტეტი.', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „საქმის განხილვის საქვეყნოობა“?', 'hard', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 13 ადგენს, რომ სასამართლოში ყველა საქმე განიხილება ღია სხდომაზე.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 13', '', '2026-03-04', false, 'იმ რაიონულ (საქალაქო) სასამართლოში, სადაც არანაკლებ 30 მოსამართლეა, სასამართლოს თავმჯდომარეს ჰყავს 2 მოადგილე, რომელთაც იმავე სასამართლოს მოსამართლეთაგან 10 წლის ვადით თანამდებობებზე ნიშნავს საქართველოს იუსტიციის უმაღლესი საბჭო დასაბუთებული გადაწყვეტილებით.', 'მოსამართლის თანამდებობიდან გათავისუფლების, უზენაესი სასამართლოს თავმჯდომარისა და უზენაესი სასამართლოს წევრის უფლებამოსილების შეწყვეტის საფუძვლებია:', 'სასამართლოში ყველა საქმე განიხილება ღია სხდომაზე.', 'საქართველოს მოსამართლეთა კონფერენცია:', 'C'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „სასამართლო სხდომის მასობრივი ინფორმაციის საშუალებებით გაშუქება“?', 'medium', 'სწორი პასუხია D, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 13¹ ადგენს, რომ სასამართლო ვალდებულია უზრუნველყოს სასამართლო პროცესის აუდიო-, ვიდეოჩაწერა.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 13¹', '', '2026-03-04', false, 'იმ რაიონულ (საქალაქო) სასამართლოში, სადაც სასამართლოს თავმჯდომარეს ჰყავს მოადგილეები, სასამართლოს თავმჯდომარის დროებით არყოფნისას მის უფლებამოსილებას ახორციელებს სასამართლოს თავმჯდომარის პირველი მოადგილე, ხოლო რაიონული (საქალაქო) სასამართლოს თავმჯდომარის პირველი მოადგილის არყოფნისას − სასამართლოს თავმჯდომარის მოადგილე.', 'სასამართლოს ლიკვიდაციის, აგრეთვე მოსამართლის თანამდებობის შემცირების შემთხვევაში მოსამართლეს მისივე წინასწარი წერილობითი თანხმობით, საქართველოს კანონმდებლობით დადგენილი წესით შეიძლება დაეკისროს შესაბამისი ან ქვემდგომი ინსტანციის სასამართლოს მოსამართლის უფლებამოსილების განხორციელება.', 'საქართველოს მოსამართლეთა კონფერენცია, როგორც წესი, მოიწვევა წელიწადში ერთხელ.', 'სასამართლო ვალდებულია უზრუნველყოს სასამართლო პროცესის აუდიო-, ვიდეოჩაწერა.', 'D'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „სასამართლო მედიაციის პროგრამა“?', 'easy', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 13² ადგენს, რომ რაიონული (საქალაქო) სასამართლო, სააპელაციო სასამართლო ვალდებულია შესაბამის სასამართლოში „მედიაციის შესახებ“ საქართველოს კანონის საფუძველზე განახორციელოს სასამართლო მედიაციის პროგრამით გათვალისწინებული ღონისძიებები და მედიაციის განვითარებისათვის საჭირო სხვა ღონისძიებები.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 13²', '', '2026-03-04', false, 'რაიონული (საქალაქო) სასამართლო, სააპელაციო სასამართლო ვალდებულია შესაბამის სასამართლოში „მედიაციის შესახებ“ საქართველოს კანონის საფუძველზე განახორციელოს სასამართლო მედიაციის პროგრამით გათვალისწინებული ღონისძიებები და მედიაციის განვითარებისათვის საჭირო სხვა ღონისძიებები.', 'მოსამართლის თანამდებობის დასაკავებლად მოსამართლეობის საკვალიფიკაციო გამოცდის ჩაბარებისგან თავისუფლდება:', 'საქართველოს საერთო სასამართლოების მოსამართლეთა სადისციპლინო კოლეგია საქართველოს იუსტიციის უმაღლესი საბჭოს წარდგინებას იხილავს მისი მიღებიდან 10 სამუშაო დღის ვადაში, ამ კანონით დადგენილი საერთო წესით.', 'იუსტიციის უმაღლესი სკოლა (შემდგომ – სკოლა), როგორც საჯარო სამართლის იურიდიული პირი, იქმნება ამ კანონის საფუძველზე.', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „საქართველოს უზენაესი სასამართლო“?', 'hard', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 14 ადგენს, რომ საქართველოს უზენაესი სასამართლო (შემდგომში – უზენაესი სასამართლო) საქართველოს მთელ ტერიტორიაზე მართლმსაჯულების განხორციელების უმაღლესი და საბოლოო ინსტანციის საკასაციო სასამართლოა.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 14', '', '2026-03-04', false, 'საქართველოს იუსტიციის უმაღლესი საბჭო შერჩევის პროცედურის დაწყებას აცხადებს საქართველოს ოფიციალური ბეჭდვითი ორგანოს და თავისი ოფიციალური ვებგვერდის მეშვეობით და შესაბამის ინფორმაციას აწვდის საზოგადოებრივ მაუწყებელს.', 'საქართველოს უზენაესი სასამართლო (შემდგომში – უზენაესი სასამართლო) საქართველოს მთელ ტერიტორიაზე მართლმსაჯულების განხორციელების უმაღლესი და საბოლოო ინსტანციის საკასაციო სასამართლოა.', 'საქართველოს იუსტიციის უმაღლესი საბჭო ანგარიშვალდებულია საქართველოს მოსამართლეთა კონფერენციის წინაშე.', 'სკოლის მართვის ორგანოებია: სკოლის დამოუკიდებელი საბჭო და სკოლის დირექცია.', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „უზენაესი სასამართლოს სტრუქტურა“?', 'medium', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 15 ადგენს, რომ უზენაეს სასამართლოში, საქართველოს იუსტიციის უმაღლესი საბჭოს გადაწყვეტილებით, შეიძლება განხორციელდეს მოსამართლეების უფრო ვიწრო სპეციალიზაცია.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 15', '', '2026-03-04', false, 'უზენაესი სასამართლოს მოსამართლის თანამდებობაზე ასარჩევად საქართველოს პარლამენტისთვის წარსადგენი კანდიდატების შესახებ ამ მუხლის შესაბამისად მოძიებული ინფორმაცია საქართველოს იუსტიციის უმაღლესი საბჭოს წევრთა მიერ კანდიდატების შესაფასებლად გამოიყენება.', 'საქართველოს იუსტიციის უმაღლესი საბჭოს წევრის უფლებამოსილების შეწყვეტის საფუძვლებია:', 'უზენაეს სასამართლოში, საქართველოს იუსტიციის უმაღლესი საბჭოს გადაწყვეტილებით, შეიძლება განხორციელდეს მოსამართლეების უფრო ვიწრო სპეციალიზაცია.', 'სკოლის საქმიანობის მიმართულებებს განსაზღვრავს, კოორდინაციას უწევს და მათ აღსრულებას ზედამხედველობს სკოლის დამოუკიდებელი საბჭო (შემდგომ – დამოუკიდებელი საბჭო).', 'C'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „უზენაესი სასამართლოს პალატა“?', 'hard', 'სწორი პასუხია D, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 16 ადგენს, რომ უზენაესი სასამართლოს პალატა (გარდა დიდი პალატისა) საქმეს განიხილავს 3 მოსამართლის შემადგენლობით.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 16', '', '2026-03-04', false, 'კანდიდატების შერჩევის პროცესში საქართველოს იუსტიციის უმაღლესი საბჭოს წევრი მიკერძოებული იყო;', 'საქართველოს იუსტიციის უმაღლესი საბჭო:', 'დამოუკიდებელი საბჭოს წევრის თავისი უფლებამოსილების განხორციელებისგან გათავისუფლების საფუძვლებია:', 'უზენაესი სასამართლოს პალატა (გარდა დიდი პალატისა) საქმეს განიხილავს 3 მოსამართლის შემადგენლობით.', 'D'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „უზენაესი სასამართლოს დიდი პალატა“?', 'hard', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 17 ადგენს, რომ უზენაესი სასამართლოს დიდი პალატა არის საკასაციო ინსტანციის სასამართლო, რომელიც საქართველოს საპროცესო კანონმდებლობით დადგენილი წესით განიხილავს ამ კანონის მე-16 მუხლის მე-3 პუნქტით და მე-17 მუხლის მე-5 პუნქტით განსაზღვრულ, განსაკუთრებით რთული კატეგორიის საქმეებს.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 17', '', '2026-03-04', false, 'უზენაესი სასამართლოს დიდი პალატა არის საკასაციო ინსტანციის სასამართლო, რომელიც საქართველოს საპროცესო კანონმდებლობით დადგენილი წესით განიხილავს ამ კანონის მე-16 მუხლის მე-3 პუნქტით და მე-17 მუხლის მე-5 პუნქტით განსაზღვრულ, განსაკუთრებით რთული კატეგორიის საქმეებს.', 'პირი რაიონული (საქალაქო) ან სააპელაციო სასამართლოს მოსამართლის ვაკანტურ თანამდებობაზე განწესდება უვადოდ.', 'შეტყობინება გულისხმობს საქართველოს იუსტიციის უმაღლესი საბჭოსთვის სამეცნიერო ან პედაგოგიური საქმიანობის ან „კორუფციის წინააღმდეგ ბრძოლის შესახებ“ საქართველოს კანონით გათვალისწინებული და ნებადართული სარგებლის თაობაზე შემდეგი ინფორმაციის წარდგენას:', 'დამოუკიდებელი საბჭოს სხდომა, როგორც წესი, მოიწვევა არანაკლებ წელიწადში ერთხელ.', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „უზენაესი სასამართლოს პლენუმი“?', 'hard', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 18 ადგენს, რომ უზენაესი სასამართლოს პლენუმი შედგება უზენაესი სასამართლოს თავმჯდომარის, მისი პირველი მოადგილისა და მოადგილეების, უზენაესი სასამართლოს წევრებისა და სააპელაციო სასამართლოების თავმჯდომარეებისაგან.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 18', '', '2026-03-04', false, 'მოსამართლეობის კანდიდატი და რაიონული (საქალაქო) სასამართლოს მოსამართლის თანამდებობაზე 2025 წლის 1 იანვრამდე 3 წლის ვადით განწესებული მოსამართლე ფასდებიან 2 ძირითადი კრიტერიუმით − კეთილსინდისიერებისა და კომპეტენტურობის კრიტერიუმებით.', 'უზენაესი სასამართლოს პლენუმი შედგება უზენაესი სასამართლოს თავმჯდომარის, მისი პირველი მოადგილისა და მოადგილეების, უზენაესი სასამართლოს წევრებისა და სააპელაციო სასამართლოების თავმჯდომარეებისაგან.', 'საქართველოს იუსტიციის უმაღლესი საბჭო უფლებამოსილია განიხილოს საკითხი და მიიღოს გადაწყვეტილება, თუ მის სხდომას ესწრება საბჭოს წევრთა ნახევარზე მეტი.', 'სკოლის დირექცია შედგება სკოლის დირექტორისგან, მისი მოადგილეებისა და სტაჟირების ხელმძღვანელისგან.', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „უზენაესი სასამართლოს სადისციპლინო პალატა“?', 'easy', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 19 ადგენს, რომ უზენაესი სასამართლოს სადისციპლინო პალატას 3 წევრის შემადგენლობით, 5 წლის ვადით ირჩევს უზენაესი სასამართლოს პლენუმი.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 19', '', '2026-03-04', false, 'თუ საქართველოს იუსტიციის უმაღლესი საბჭოს წევრი არის მოსამართლეობის კანდიდატის ოჯახის წევრი, პირდაპირი აღმავალი ან დამავალი შტოს ნათესავი, და, ძმა, მშობლის ან შვილის გერი, მეუღლის და, ძმა ან მშობელი, იგი არ მონაწილეობს მოსამართლის ვაკანტური თანამდებობის დასაკავებელი კონკურსის პროცედურაში.', 'საქართველოს იუსტიციის უმაღლესი საბჭოს მდივანს 4 წლის ვადით ირჩევს საქართველოს მოსამართლეთა კონფერენცია მის მიერ არჩეულ საქართველოს იუსტიციის უმაღლესი საბჭოს წევრთაგან.', 'უზენაესი სასამართლოს სადისციპლინო პალატას 3 წევრის შემადგენლობით, 5 წლის ვადით ირჩევს უზენაესი სასამართლოს პლენუმი.', 'წარმოადგენს სკოლას; უზრუნველყოფს სკოლის ფუნქციონირებას, იუსტიციის მსმენელთა სასწავლო კურსისა და გადამზადების კურსის წარმართვას;', 'C'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „უზენაესი სასამართლოს საკვალიფიკაციო პალატა“?', 'medium', 'სწორი პასუხია D, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 19¹ ადგენს, რომ უზენაესი სასამართლოს საკვალიფიკაციო პალატას 3 წევრის შემადგენლობით, 5 წლის ვადით ირჩევს უზენაესი სასამართლოს პლენუმი.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 19¹', '', '2026-03-04', false, 'უზენაესი სასამართლოს მოსამართლეს საქართველოს იუსტიციის უმაღლესი საბჭოს წარდგინებით უვადოდ, ამ კანონით დადგენილი ასაკის მიღწევამდე, სრული შემადგენლობის უმრავლესობით ირჩევს საქართველოს პარლამენტი.', 'მოსამართლეობის საკვალიფიკაციო გამოცდის ორგანიზებისა და ჩატარების მიზნით საქართველოს იუსტიციის უმაღლესი საბჭო თავისი რეგლამენტით დადგენილი წესით ქმნის საკვალიფიკაციო საგამოცდო კომისიას და ამტკიცებს საკვალიფიკაციო საგამოცდო კომისიის შემადგენლობასა და დებულებას.', 'სკოლის დირექტორის მოადგილე უზრუნველყოფს სასწავლო და გადამზადების პროგრამების განხორციელებას.', 'უზენაესი სასამართლოს საკვალიფიკაციო პალატას 3 წევრის შემადგენლობით, 5 წლის ვადით ირჩევს უზენაესი სასამართლოს პლენუმი.', 'D'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „უზენაესი სასამართლოს პალატების თავმჯდომარეები“?', 'hard', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 20 ადგენს, რომ უზენაესი სასამართლოს პალატებს ჰყავთ თავმჯდომარეები.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 20', '', '2026-03-04', false, 'უზენაესი სასამართლოს პალატებს ჰყავთ თავმჯდომარეები.', 'მოსამართლის საქმიანობის შეფასების მიზანია თანამდებობაზე უვადოდ გასამწესებლად ღირსეული, კვალიფიციური და კეთილსინდისიერი მოსამართლის შერჩევის გზით დამოუკიდებელი და კვალიფიციური მართლმსაჯულების უზრუნველყოფა.', 'მოსამართლეობის საკვალიფიკაციო გამოცდის ჩაბარების უფლება აქვს 25 წლის ასაკს მიღწეულ, უმაღლესი იურიდიული განათლების მქონე საქართველოს ყველა მოქალაქეს.', 'სკოლის დირექტორის, სკოლის დირექტორის მოადგილის, სტაჟირების ხელმძღვანელის თანამდებობიდან გათავისუფლების საფუძვლებია:', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „უზენაესი სასამართლოს თავმჯდომარე“?', 'medium', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 21 ადგენს, რომ საერთო ხელმძღვანელობას და ორგანიზებას უწევს უზენაესი სასამართლოს მუშაობას;', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 21', '', '2026-03-04', false, 'შემფასებლები მოსამართლის საქმიანობას აფასებენ პარალელურად, ერთმანეთისაგან დამოუკიდებლად.', 'საერთო ხელმძღვანელობას და ორგანიზებას უწევს უზენაესი სასამართლოს მუშაობას;', 'საქართველოს საერთო სასამართლოების მატერიალურ-ტექნიკურ უზრუნველყოფას ახორციელებს საქართველოს იუსტიციის უმაღლეს საბჭოსთან არსებული საჯარო სამართლის იურიდიული პირი − საერთო სასამართლოების დეპარტამენტი (შემდგომ − საერთო სასამართლოების დეპარტამენტი).', 'სკოლის სტრუქტურა და სკოლის სტრუქტურული ერთეულების საქმიანობის წესი განისაზღვრება სკოლის წესდებით.', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „სააპელაციო სასამართლო“?', 'medium', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 22 ადგენს, რომ სააპელაციო სასამართლო იქმნება და მისი სამოქმედო ტერიტორია განისაზღვრება საქართველოს იუსტიციის უმაღლესი საბჭოს გადაწყვეტილებით.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 22', '', '2026-03-04', false, 'მოსამართლეს უფლება აქვს, თანამდებობაზე მისი უვადოდ გამწესებაზე უარის თქმის შესახებ საქართველოს იუსტიციის უმაღლესი საბჭოს გადაწყვეტილება გაასაჩივროს უზენაესი სასამართლოს საკვალიფიკაციო პალატაში, თუ მიაჩნია, რომ:', 'საერთო სასამართლოების დეპარტამენტი:', 'სააპელაციო სასამართლო იქმნება და მისი სამოქმედო ტერიტორია განისაზღვრება საქართველოს იუსტიციის უმაღლესი საბჭოს გადაწყვეტილებით.', 'სკოლის საქმიანობასთან დაკავშირებული ხარჯები გათვალისწინებულია საერთო სასამართლოების ბიუჯეტში ცალკე სტრიქონით.', 'C'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „სააპელაციო სასამართლოს შემადგენლობა“?', 'medium', 'სწორი პასუხია D, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 23 ადგენს, რომ სააპელაციო სასამართლოს მოსამართლეთა რაოდენობას განსაზღვრავს საქართველოს იუსტიციის უმაღლესი საბჭო.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 23', '', '2026-03-04', false, 'საჩივარი ზეპირი მოსმენით განიხილება უზენაესი სასამართლოს საკვალიფიკაციო პალატის ღია სხდომაზე.', 'მართლმსაჯულების დაუბრკოლებლად განხორციელების, სასამართლო პრაქტიკის შესწავლისა და განზოგადების, სასამართლო სტატისტიკის ანალიზის, აგრეთვე სასამართლოს სხვა საქმიანობის უზრუნველყოფის მიზნით საქართველოს საერთო სასამართლოებში მოქმედებენ სასამართლოთა აპარატები.', 'სკოლაში პირი იუსტიციის მსმენელად კონკურსის წესით მიიღება.', 'სააპელაციო სასამართლოს მოსამართლეთა რაოდენობას განსაზღვრავს საქართველოს იუსტიციის უმაღლესი საბჭო.', 'D'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „სააპელაციო სასამართლოს უფლებამოსილება“?', 'easy', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 24 ადგენს, რომ სააპელაციო სასამართლო საპროცესო კანონით დადგენილი წესით, კოლეგიურად, 3 მოსამართლის შემადგენლობით განიხილავს სააპელაციო საჩივრებს რაიონული (საქალაქო) სასამართლოების გადაწყვეტილებებზე.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 24', '', '2026-03-04', false, 'სააპელაციო სასამართლო საპროცესო კანონით დადგენილი წესით, კოლეგიურად, 3 მოსამართლის შემადგენლობით განიხილავს სააპელაციო საჩივრებს რაიონული (საქალაქო) სასამართლოების გადაწყვეტილებებზე.', 'მოსამართლის თანამდებობაზე უვადოდ გამწესებაზე უარის თქმის შესახებ საქართველოს იუსტიციის უმაღლესი საბჭოს განმეორებითი გადაწყვეტილება საჩივრდება მოსამართლის თანამდებობაზე უვადოდ გამწესებაზე უარის თქმის შესახებ საქართველოს იუსტიციის უმაღლესი საბჭოს გადაწყვეტილების გასაჩივრებისათვის ამ კანონით დადგენილი წესით.', 'ანაზღაურებადი სტაჟირებისას პირი ინიშნება სასამართლოს აპარატის შესაბამის თანამდებობაზე.', 'სკოლაში მისაღებ კონკურსს ატარებს სკოლა.', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „სააპელაციო სასამართლოს თავმჯდომარის უფლებამოსილება“?', 'hard', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 25 ადგენს, რომ სააპელაციო სასამართლოს თავმჯდომარე:', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 25', '', '2026-03-04', false, 'შემფასებლის საქმიანობაში უკანონო ჩარევა დაუშვებელია და იწვევს საქართველოს სისხლის სამართლის კოდექსით გათვალისწინებულ პასუხისმგებლობას.', 'სააპელაციო სასამართლოს თავმჯდომარე:', 'სასამართლოში საქმეები იხილება სასამართლო სხდომის მდივნის მონაწილეობით.', 'სკოლაში მისაღები კონკურსის გამოცხადებამდე დამოუკიდებელი საბჭო დასაბუთებული გადაწყვეტილებით, სკოლის დაფინანსებისა და ინფრასტრუქტურული შესაძლებლობების გათვალისწინებით განსაზღვრავს სკოლაში მისაღებ იუსტიციის მსმენელთა საერთო რაოდენობას.', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „სააპელაციო სასამართლოს თავმჯდომარის პირველი მოადგილის/მოადგილის უფლებამოსილება“?', 'medium', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 26 ადგენს, რომ სააპელაციო სასამართლოს თავმჯდომარის პირველი მოადგილე:', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 26', '', '2026-03-04', false, 'ვაკანსიის წარმოშობის შემთხვევაში შესაძლებელია თანამდებობაზე დანიშნული მოსამართლე მისივე თანხმობით კონკურსის გარეშე დაინიშნოს რაიონული (საქალაქო) ან სააპელაციო სასამართლოს მოსამართლედ.', 'რაიონულ (საქალაქო), სააპელაციო და უზენაეს სასამართლოებში მოსამართლეთა შორის საქმეები ნაწილდება ავტომატურად, ელექტრონული სისტემის მეშვეობით, შემთხვევითი განაწილების პრინციპის დაცვით.', 'სააპელაციო სასამართლოს თავმჯდომარის პირველი მოადგილე:', 'იუსტიციის მსმენელი არის პირი, რომელიც კონკურსის გავლის შედეგად, საქართველოს იუსტიციის უმაღლესი საბჭოს გადაწყვეტილებით ჩაირიცხა სკოლაში სასწავლებლად.', 'C'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „რაიონული (საქალაქო) სასამართლოს შექმნა“?', 'medium', 'სწორი პასუხია D, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 27 ადგენს, რომ რაიონული (საქალაქო) სასამართლო იქმნება და მისი სამოქმედო ტერიტორია განისაზღვრება საქართველოს იუსტიციის უმაღლესი საბჭოს გადაწყვეტილებით.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 27', '', '2026-03-04', false, 'ამასთანავე, ეს წესი არ გამოიყენება იმ შემთხვევაში, თუ მოსამართლე თავისი ინიციატივით მიმართავს საქართველოს იუსტიციის უმაღლეს საბჭოს მისი სხვა სასამართლოში მივლინების თაობაზე.', 'სასამართლოების მანდატურის სამსახურების საქმიანობის საერთო ხელმძღვანელობასა და კონტროლს ახორციელებს საქართველოს იუსტიციის უმაღლესი საბჭოს შესაბამისი სტრუქტურული ერთეული.', 'იუსტიციის მსმენელი სასწავლო კურსის გავლისას იღებს სახელმწიფო სტიპენდიას, რომლის ოდენობა არ შეიძლება იყოს პირველი ინსტანციის სასამართლოს მოსამართლის მინიმალური ხელფასის 1/3-ზე ნაკლები.', 'რაიონული (საქალაქო) სასამართლო იქმნება და მისი სამოქმედო ტერიტორია განისაზღვრება საქართველოს იუსტიციის უმაღლესი საბჭოს გადაწყვეტილებით.', 'D'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლეთა რაოდენობა რაიონულ (საქალაქო) სასამართლოში“?', 'medium', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 28 ადგენს, რომ რაიონული (საქალაქო) სასამართლო შედგება არანაკლებ 2 მოსამართლისაგან.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 28', '', '2026-03-04', false, 'რაიონული (საქალაქო) სასამართლო შედგება არანაკლებ 2 მოსამართლისაგან.', 'უზენაესი სასამართლოს თავმჯდომარე და უზენაესი სასამართლოს წევრები ფიცს დებენ საქართველოს პარლამენტის წინაშე, ხოლო სააპელაციო და რაიონული (საქალაქო) სასამართლოების მოსამართლეები – საქართველოს იუსტიციის უმაღლესი საბჭოს წინაშე.', 'სასამართლოს მანდატურის სამსახურის უფროსს თანამდებობაზე ნიშნავს და თანამდებობიდან ათავისუფლებს შესაბამისად სასამართლოს თავმჯდომარე ან საქართველოს იუსტიციის უმაღლესი საბჭოს მდივანი.', 'იუსტიციის მსმენელი ვალდებულია დაიცვას დისციპლინური ნორმები.', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „საქმეთა განხილვა რაიონულ (საქალაქო) სასამართლოში“?', 'hard', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 29 ადგენს, რომ რაიონული (საქალაქო) სასამართლო არის პირველი ინსტანციის სასამართლო, რომელიც მისი განსჯადობისთვის მიკუთვნებულ საქმეს საქართველოს საპროცესო კანონმდებლობით დადგენილი წესით განიხილავს ერთპიროვნულად ან, კანონით გათვალისწინებულ შემთხვევაში, – კოლეგიურად, 3 მოსამართლის შემადგენლობით.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 29', '', '2026-03-04', false, 'მოსამართლის თანამდებობა შეუთავსებელია ნებისმიერ სხვა თანამდებობასთან და ანაზღაურებად საქმიანობასთან, გარდა საქართველოს კონსტიტუციით დადგენილი გამონაკლისისა.', 'რაიონული (საქალაქო) სასამართლო არის პირველი ინსტანციის სასამართლო, რომელიც მისი განსჯადობისთვის მიკუთვნებულ საქმეს საქართველოს საპროცესო კანონმდებლობით დადგენილი წესით განიხილავს ერთპიროვნულად ან, კანონით გათვალისწინებულ შემთხვევაში, – კოლეგიურად, 3 მოსამართლის შემადგენლობით.', 'უზრუნველყოფს მოსამართლეების, სასამართლო პროცესის მონაწილეებისა და მოწმეების უსაფრთხოებას;', 'იუსტიციის მსმენელს სკოლაში სწავლის პერიოდი სპეციალობით მუშაობის სტაჟში ჩაეთვლება.', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლეთა სპეციალიზაცია“?', 'easy', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 30 ადგენს, რომ რაიონულ (საქალაქო) სასამართლოში, სადაც ორი მოსამართლეა, ერთი განიხილავს სისხლის სამართლის საქმეებს, ხოლო მეორე – სამოქალაქო და სხვა კატეგორიის საქმეებს, გარდა საქართველოს საპროცესო კანონმდებლობით დადგენილი შემთხვევებისა.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 30', '', '2026-03-04', false, 'დაუშვებელია მისი სისხლის სამართლის პასუხისგებაში მიცემა, დაკავება ან დაპატიმრება, საცხოვრებელი ან სამუშაო ადგილის, მანქანის ან პირადი გაჩხრეკა საქართველოს იუსტიციის უმაღლესი საბჭოს თანხმობის გარეშე.', 'სასამართლოს მანდატურს ფიზიკური ძალის, სპეციალური საშუალებებისა და იარაღის გამოყენების უფლება აქვს მხოლოდ იმ შემთხვევაში, როდესაც სხვა, შედარებით მსუბუქი ზომების გამოყენებით შეუძლებელია მისი სამსახურებრივი მოვალეობების შესრულება.', 'რაიონულ (საქალაქო) სასამართლოში, სადაც ორი მოსამართლეა, ერთი განიხილავს სისხლის სამართლის საქმეებს, ხოლო მეორე – სამოქალაქო და სხვა კატეგორიის საქმეებს, გარდა საქართველოს საპროცესო კანონმდებლობით დადგენილი შემთხვევებისა.', 'იუსტიციის მსმენელს უფლება აქვს, გაეცნოს მის შესახებ სკოლაში არსებულ ნებისმიერ ინფორმაციასა და ოფიციალურ დოკუმენტს და მიიღოს მათი ასლები.', 'C'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „რაიონული (საქალაქო) სასამართლოს განსჯადობა“?', 'medium', 'სწორი პასუხია D, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 31 ადგენს, რომ რაიონული (საქალაქო) სასამართლოს განსჯადობა, ასევე მაგისტრატი მოსამართლის განსჯადობა განისაზღვრება კანონით.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 31', '', '2026-03-04', false, 'რაიონული (საქალაქო) სასამართლოს მოსამართლე შეიძლება დაინიშნოს სააპელაციო სასამართლოში, თუ იგი რაიონულ (საქალაქო) სასამართლოში მოსამართლის უფლებამოსილებას ახორციელებდა არანაკლებ 3 წლის განმავლობაში.', 'საქართველოს მოსამართლეთა კონფერენცია არის საქართველოს საერთო სასამართლოების მოსამართლეთა თვითმმართველობის ორგანო.', 'სკოლაში სწავლების ხანგრძლივობაა 16 თვე.', 'რაიონული (საქალაქო) სასამართლოს განსჯადობა, ასევე მაგისტრატი მოსამართლის განსჯადობა განისაზღვრება კანონით.', 'D'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „რაიონული (საქალაქო) სასამართლოს თავმჯდომარე“?', 'hard', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 32 ადგენს, რომ რაიონული (საქალაქო) სასამართლოს თავმჯდომარეს შესაბამისი სასამართლოს მოსამართლეთაგან, ხოლო იმ სასამართლოს თავმჯდომარეს, სადაც შექმნილია სასამართლო კოლეგიები, – მათ შორის, სასამართლო კოლეგიების თავმჯდომარეთაგან, 10 წლის ვადით თანამდებობაზე ნიშნავს საქართველოს იუსტიციის უმაღლესი საბჭო დასაბუთებული გადაწყვეტილებით.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 32', '', '2026-03-04', false, 'რაიონული (საქალაქო) სასამართლოს თავმჯდომარეს შესაბამისი სასამართლოს მოსამართლეთაგან, ხოლო იმ სასამართლოს თავმჯდომარეს, სადაც შექმნილია სასამართლო კოლეგიები, – მათ შორის, სასამართლო კოლეგიების თავმჯდომარეთაგან, 10 წლის ვადით თანამდებობაზე ნიშნავს საქართველოს იუსტიციის უმაღლესი საბჭო დასაბუთებული გადაწყვეტილებით.', 'უზენაესი სასამართლოს თავმჯდომარისა და უზენაესი სასამართლოს მოსამართლის თანამდებობიდან გადაყენება შეიძლება მხოლოდ იმპიჩმენტის წესით.', 'საქართველოს მოსამართლეთა კონფერენციის სისტემაში, ამ კანონის 63-ე მუხლით განსაზღვრული ფუნქციების შესრულების ხელშეწყობის მიზნით, იქმნება ადმინისტრაციული კომიტეტი.', 'იუსტიციის მსმენელის მომზადების სასწავლო პროგრამამ უნდა უზრუნველყოს ამ კანონის 35​1 მუხლით გათვალისწინებული კრიტერიუმების შესაბამისი თეორიული ცოდნის გაღრმავება, პრაქტიკული უნარებისა და თვისებების განვითარება.', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „რაიონული (საქალაქო) სასამართლოს თავმჯდომარის მოადგილეები“?', 'hard', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 32¹ ადგენს, რომ იმ რაიონულ (საქალაქო) სასამართლოში, სადაც არანაკლებ 30 მოსამართლეა, სასამართლოს თავმჯდომარეს ჰყავს 2 მოადგილე, რომელთაც იმავე სასამართლოს მოსამართლეთაგან 10 წლის ვადით თანამდებობებზე ნიშნავს საქართველოს იუსტიციის უმაღლესი საბჭო დასაბუთებული გადაწყვეტილებით.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 32¹', '', '2026-03-04', false, 'მოსამართლის თანამდებობიდან გათავისუფლების, უზენაესი სასამართლოს თავმჯდომარისა და უზენაესი სასამართლოს წევრის უფლებამოსილების შეწყვეტის საფუძვლებია:', 'იმ რაიონულ (საქალაქო) სასამართლოში, სადაც არანაკლებ 30 მოსამართლეა, სასამართლოს თავმჯდომარეს ჰყავს 2 მოადგილე, რომელთაც იმავე სასამართლოს მოსამართლეთაგან 10 წლის ვადით თანამდებობებზე ნიშნავს საქართველოს იუსტიციის უმაღლესი საბჭო დასაბუთებული გადაწყვეტილებით.', 'საქართველოს მოსამართლეთა კონფერენცია:', 'სკოლაში სწავლების ფორმებია: სემინარი, სასამართლო პროცესის სიმულაცია, დისკუსია, სწავლება სასამართლო გადაწყვეტილების მიღებისა და მისი დასაბუთების საკითხებზე, საღამოს სწავლება, დისტანციური სწავლება, აგრეთვე სხვა ფორმები, რომლებსაც სკოლის დირექტორის წარდგინებით ამტკიცებს დამოუკიდებელი საბჭო.', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „რაიონული (საქალაქო) სასამართლოს თავმჯდომარის/თავმჯდომარის პირველი მოადგილის/მოადგილის/სასამართლო კოლეგიის თავმჯდომარის უფლებამოსილების განხორციელება“?', 'hard', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 33 ადგენს, რომ იმ რაიონულ (საქალაქო) სასამართლოში, სადაც სასამართლოს თავმჯდომარეს ჰყავს მოადგილეები, სასამართლოს თავმჯდომარის დროებით არყოფნისას მის უფლებამოსილებას ახორციელებს სასამართლოს თავმჯდომარის პირველი მოადგილე, ხოლო რაიონული (საქალაქო) სასამართლოს თავმჯდომარის პირველი მოადგილის არყოფნისას − სასამართლოს თავმჯდომარის მოადგილე.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 33', '', '2026-03-04', false, 'სასამართლოს ლიკვიდაციის, აგრეთვე მოსამართლის თანამდებობის შემცირების შემთხვევაში მოსამართლეს მისივე წინასწარი წერილობითი თანხმობით, საქართველოს კანონმდებლობით დადგენილი წესით შეიძლება დაეკისროს შესაბამისი ან ქვემდგომი ინსტანციის სასამართლოს მოსამართლის უფლებამოსილების განხორციელება.', 'საქართველოს მოსამართლეთა კონფერენცია, როგორც წესი, მოიწვევა წელიწადში ერთხელ.', 'იმ რაიონულ (საქალაქო) სასამართლოში, სადაც სასამართლოს თავმჯდომარეს ჰყავს მოადგილეები, სასამართლოს თავმჯდომარის დროებით არყოფნისას მის უფლებამოსილებას ახორციელებს სასამართლოს თავმჯდომარის პირველი მოადგილე, ხოლო რაიონული (საქალაქო) სასამართლოს თავმჯდომარის პირველი მოადგილის არყოფნისას − სასამართლოს თავმჯდომარის მოადგილე.', 'სკოლაში იუსტიციის მსმენელთა სწავლებას წარმართავენ სკოლის მასწავლებლები.', 'C'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლეობის კანდიდატისთვის დადგენილი მოთხოვნები“?', 'hard', 'სწორი პასუხია D, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 34 ადგენს, რომ მოსამართლის თანამდებობის დასაკავებლად მოსამართლეობის საკვალიფიკაციო გამოცდის ჩაბარებისგან თავისუფლდება:', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 34', '', '2026-03-04', false, 'საქართველოს საერთო სასამართლოების მოსამართლეთა სადისციპლინო კოლეგია საქართველოს იუსტიციის უმაღლესი საბჭოს წარდგინებას იხილავს მისი მიღებიდან 10 სამუშაო დღის ვადაში, ამ კანონით დადგენილი საერთო წესით.', 'იუსტიციის უმაღლესი სკოლა (შემდგომ – სკოლა), როგორც საჯარო სამართლის იურიდიული პირი, იქმნება ამ კანონის საფუძველზე.', 'სკოლაში თეორიული კურსის დასასრულს იუსტიციის მსმენელი აბარებს გამოცდას, რომლის მიზანია სკოლაში სწავლის პერიოდში მიღებული თეორიული ცოდნის შეფასება.', 'მოსამართლის თანამდებობის დასაკავებლად მოსამართლეობის საკვალიფიკაციო გამოცდის ჩაბარებისგან თავისუფლდება:', 'D'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „უზენაესი სასამართლოს მოსამართლის თანამდებობაზე ასარჩევად საქართველოს პარლამენტისთვის წარსადგენი კანდიდატების შერჩევის წესი“?', 'easy', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 34¹ ადგენს, რომ საქართველოს იუსტიციის უმაღლესი საბჭო შერჩევის პროცედურის დაწყებას აცხადებს საქართველოს ოფიციალური ბეჭდვითი ორგანოს და თავისი ოფიციალური ვებგვერდის მეშვეობით და შესაბამის ინფორმაციას აწვდის საზოგადოებრივ მაუწყებელს.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 34¹', '', '2026-03-04', false, 'საქართველოს იუსტიციის უმაღლესი საბჭო შერჩევის პროცედურის დაწყებას აცხადებს საქართველოს ოფიციალური ბეჭდვითი ორგანოს და თავისი ოფიციალური ვებგვერდის მეშვეობით და შესაბამის ინფორმაციას აწვდის საზოგადოებრივ მაუწყებელს.', 'საქართველოს იუსტიციის უმაღლესი საბჭო ანგარიშვალდებულია საქართველოს მოსამართლეთა კონფერენციის წინაშე.', 'სკოლის მართვის ორგანოებია: სკოლის დამოუკიდებელი საბჭო და სკოლის დირექცია.', 'თეორიული კურსის დამამთავრებელი გამოცდის ჩაბარების შემდეგ იუსტიციის მსმენელი გადის სტაჟირებას.', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „უზენაესი სასამართლოს მოსამართლის თანამდებობაზე ასარჩევად საქართველოს პარლამენტისთვის წარსადგენი კანდიდატების შესახებ ინფორმაციის მოძიება“?', 'hard', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 34² ადგენს, რომ უზენაესი სასამართლოს მოსამართლის თანამდებობაზე ასარჩევად საქართველოს პარლამენტისთვის წარსადგენი კანდიდატების შესახებ ამ მუხლის შესაბამისად მოძიებული ინფორმაცია საქართველოს იუსტიციის უმაღლესი საბჭოს წევრთა მიერ კანდიდატების შესაფასებლად გამოიყენება.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 34²', '', '2026-03-04', false, 'საქართველოს იუსტიციის უმაღლესი საბჭოს წევრის უფლებამოსილების შეწყვეტის საფუძვლებია:', 'უზენაესი სასამართლოს მოსამართლის თანამდებობაზე ასარჩევად საქართველოს პარლამენტისთვის წარსადგენი კანდიდატების შესახებ ამ მუხლის შესაბამისად მოძიებული ინფორმაცია საქართველოს იუსტიციის უმაღლესი საბჭოს წევრთა მიერ კანდიდატების შესაფასებლად გამოიყენება.', 'სკოლის საქმიანობის მიმართულებებს განსაზღვრავს, კოორდინაციას უწევს და მათ აღსრულებას ზედამხედველობს სკოლის დამოუკიდებელი საბჭო (შემდგომ – დამოუკიდებელი საბჭო).', 'სკოლის დირექტორი სტაჟირების ხელმძღვანელის წარდგინებით ამ კანონის 66​26 მუხლის მე-2 პუნქტით განსაზღვრულ ორგანოებში ნიშნავს სტაჟირების კოორდინატორებს.', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „უზენაესი სასამართლოს მოსამართლის თანამდებობაზე ასარჩევად საქართველოს პარლამენტისთვის წარსადგენი კანდიდატების შერჩევის პროცესში მიღებული საქართველოს იუსტიციის უმაღლესი საბჭოს წარდგინების გასაჩივრება“?', 'medium', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 34³ ადგენს, რომ კანდიდატების შერჩევის პროცესში საქართველოს იუსტიციის უმაღლესი საბჭოს წევრი მიკერძოებული იყო;', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 34³', '', '2026-03-04', false, 'საქართველოს იუსტიციის უმაღლესი საბჭო:', 'დამოუკიდებელი საბჭოს წევრის თავისი უფლებამოსილების განხორციელებისგან გათავისუფლების საფუძვლებია:', 'კანდიდატების შერჩევის პროცესში საქართველოს იუსტიციის უმაღლესი საბჭოს წევრი მიკერძოებული იყო;', 'სტაჟირების დასასრულს იუსტიციის მსმენელი ადგენს თავის მიერ გაწეული საქმიანობის შესახებ წერილობით ანგარიშს, აგრეთვე ასრულებს ნაშრომს სტაჟირების ორგანოს ფუნქციონირების, ამ ორგანოში არსებული პრობლემებისა და მათი გადაჭრის გზების თაობაზე.', 'C'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „რაიონული (საქალაქო) და სააპელაციო სასამართლოების მოსამართლეთა ვაკანტური თანამდებობების დაკავების წესი“?', 'medium', 'სწორი პასუხია D, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 35 ადგენს, რომ პირი რაიონული (საქალაქო) ან სააპელაციო სასამართლოს მოსამართლის ვაკანტურ თანამდებობაზე განწესდება უვადოდ.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 35', '', '2026-03-04', false, 'შეტყობინება გულისხმობს საქართველოს იუსტიციის უმაღლესი საბჭოსთვის სამეცნიერო ან პედაგოგიური საქმიანობის ან „კორუფციის წინააღმდეგ ბრძოლის შესახებ“ საქართველოს კანონით გათვალისწინებული და ნებადართული სარგებლის თაობაზე შემდეგი ინფორმაციის წარდგენას:', 'დამოუკიდებელი საბჭოს სხდომა, როგორც წესი, მოიწვევა არანაკლებ წელიწადში ერთხელ.', 'სკოლა სტაჟირების დასასრულს იუსტიციის მსმენელთათვის ატარებს სემინარებს, რომელთა მიზანია მათ მიერ თეორიული კურსისა და სტაჟირების გავლის დროს მიღებული ცოდნისა და გამოცდილების განზოგადება, აგრეთვე იუსტიციის მსმენელების სკოლის დამამთავრებელი გამოცდისათვის მომზადება.', 'პირი რაიონული (საქალაქო) ან სააპელაციო სასამართლოს მოსამართლის ვაკანტურ თანამდებობაზე განწესდება უვადოდ.', 'D'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლეობის კანდიდატისა და რაიონული (საქალაქო) ან სააპელაციო სასამართლოს მოსამართლის თანამდებობაზე 3 წლის ვადით განწესებული მოსამართლის შეფასების კრიტერიუმები, მათი მახასიათებლები და შეფასების სისტემა“?', 'hard', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 35¹ ადგენს, რომ მოსამართლეობის კანდიდატი და რაიონული (საქალაქო) სასამართლოს მოსამართლის თანამდებობაზე 2025 წლის 1 იანვრამდე 3 წლის ვადით განწესებული მოსამართლე ფასდებიან 2 ძირითადი კრიტერიუმით − კეთილსინდისიერებისა და კომპეტენტურობის კრიტერიუმებით.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 35¹', '', '2026-03-04', false, 'მოსამართლეობის კანდიდატი და რაიონული (საქალაქო) სასამართლოს მოსამართლის თანამდებობაზე 2025 წლის 1 იანვრამდე 3 წლის ვადით განწესებული მოსამართლე ფასდებიან 2 ძირითადი კრიტერიუმით − კეთილსინდისიერებისა და კომპეტენტურობის კრიტერიუმებით.', 'საქართველოს იუსტიციის უმაღლესი საბჭო უფლებამოსილია განიხილოს საკითხი და მიიღოს გადაწყვეტილება, თუ მის სხდომას ესწრება საბჭოს წევრთა ნახევარზე მეტი.', 'სკოლის დირექცია შედგება სკოლის დირექტორისგან, მისი მოადგილეებისა და სტაჟირების ხელმძღვანელისგან.', 'სკოლაში სწავლის დასასრულს იუსტიციის მსმენელი აბარებს სკოლის დამამთავრებელ გამოცდას, რომლის დანიშნულებაა იუსტიციის მსმენელის მიერ მიღებული თეორიული ცოდნისა და პრაქტიკული გამოცდილების შეფასება.', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „ინტერესთა შეუთავსებლობა“?', 'hard', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 35³ ადგენს, რომ თუ საქართველოს იუსტიციის უმაღლესი საბჭოს წევრი არის მოსამართლეობის კანდიდატის ოჯახის წევრი, პირდაპირი აღმავალი ან დამავალი შტოს ნათესავი, და, ძმა, მშობლის ან შვილის გერი, მეუღლის და, ძმა ან მშობელი, იგი არ მონაწილეობს მოსამართლის ვაკანტური თანამდებობის დასაკავებელი კონკურსის პროცედურაში.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 35³', '', '2026-03-04', false, 'საქართველოს იუსტიციის უმაღლესი საბჭოს მდივანს 4 წლის ვადით ირჩევს საქართველოს მოსამართლეთა კონფერენცია მის მიერ არჩეულ საქართველოს იუსტიციის უმაღლესი საბჭოს წევრთაგან.', 'თუ საქართველოს იუსტიციის უმაღლესი საბჭოს წევრი არის მოსამართლეობის კანდიდატის ოჯახის წევრი, პირდაპირი აღმავალი ან დამავალი შტოს ნათესავი, და, ძმა, მშობლის ან შვილის გერი, მეუღლის და, ძმა ან მშობელი, იგი არ მონაწილეობს მოსამართლის ვაკანტური თანამდებობის დასაკავებელი კონკურსის პროცედურაში.', 'წარმოადგენს სკოლას; უზრუნველყოფს სკოლის ფუნქციონირებას, იუსტიციის მსმენელთა სასწავლო კურსისა და გადამზადების კურსის წარმართვას;', 'სკოლის დამამთავრებელი გამოცდის დასრულებიდან 1 თვის ვადაში სკოლის დირექტორი დამოუკიდებელ საბჭოს დასამტკიცებლად წარუდგენს იუსტიციის მსმენელთა საკვალიფიკაციო სიას.', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლის თანამდებობაზე უვადოდ განწესება“?', 'easy', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 36 ადგენს, რომ უზენაესი სასამართლოს მოსამართლეს საქართველოს იუსტიციის უმაღლესი საბჭოს წარდგინებით უვადოდ, ამ კანონით დადგენილი ასაკის მიღწევამდე, სრული შემადგენლობის უმრავლესობით ირჩევს საქართველოს პარლამენტი.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 36', '', '2026-03-04', false, 'მოსამართლეობის საკვალიფიკაციო გამოცდის ორგანიზებისა და ჩატარების მიზნით საქართველოს იუსტიციის უმაღლესი საბჭო თავისი რეგლამენტით დადგენილი წესით ქმნის საკვალიფიკაციო საგამოცდო კომისიას და ამტკიცებს საკვალიფიკაციო საგამოცდო კომისიის შემადგენლობასა და დებულებას.', 'სკოლის დირექტორის მოადგილე უზრუნველყოფს სასწავლო და გადამზადების პროგრამების განხორციელებას.', 'უზენაესი სასამართლოს მოსამართლეს საქართველოს იუსტიციის უმაღლესი საბჭოს წარდგინებით უვადოდ, ამ კანონით დადგენილი ასაკის მიღწევამდე, სრული შემადგენლობის უმრავლესობით ირჩევს საქართველოს პარლამენტი.', 'საკვალიფიკაციო სიის შედგენის დროს კოეფიციენტით ჯამდება იუსტიციის მსმენელის მიერ:', 'C'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლის საქმიანობის შეფასების მიზანი და პრინციპები“?', 'hard', 'სწორი პასუხია D, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 36¹ ადგენს, რომ მოსამართლის საქმიანობის შეფასების მიზანია თანამდებობაზე უვადოდ გასამწესებლად ღირსეული, კვალიფიციური და კეთილსინდისიერი მოსამართლის შერჩევის გზით დამოუკიდებელი და კვალიფიციური მართლმსაჯულების უზრუნველყოფა.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 36¹', '', '2026-03-04', false, 'მოსამართლეობის საკვალიფიკაციო გამოცდის ჩაბარების უფლება აქვს 25 წლის ასაკს მიღწეულ, უმაღლესი იურიდიული განათლების მქონე საქართველოს ყველა მოქალაქეს.', 'სკოლის დირექტორის, სკოლის დირექტორის მოადგილის, სტაჟირების ხელმძღვანელის თანამდებობიდან გათავისუფლების საფუძვლებია:', 'მოსამართლეობის კანდიდატის შერჩევისას გაითვალისწინება იუსტიციის მსმენელის რიგითი ნომერი იუსტიციის მსმენელთა საკვალიფიკაციო სიაში, აგრეთვე დამოუკიდებელი საბჭოს შეფასება.', 'მოსამართლის საქმიანობის შეფასების მიზანია თანამდებობაზე უვადოდ გასამწესებლად ღირსეული, კვალიფიციური და კეთილსინდისიერი მოსამართლის შერჩევის გზით დამოუკიდებელი და კვალიფიციური მართლმსაჯულების უზრუნველყოფა.', 'D'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლის საქმიანობის შეფასების პროცედურა“?', 'medium', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 36⁴ ადგენს, რომ შემფასებლები მოსამართლის საქმიანობას აფასებენ პარალელურად, ერთმანეთისაგან დამოუკიდებლად.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 36⁴', '', '2026-03-04', false, 'შემფასებლები მოსამართლის საქმიანობას აფასებენ პარალელურად, ერთმანეთისაგან დამოუკიდებლად.', 'საქართველოს საერთო სასამართლოების მატერიალურ-ტექნიკურ უზრუნველყოფას ახორციელებს საქართველოს იუსტიციის უმაღლეს საბჭოსთან არსებული საჯარო სამართლის იურიდიული პირი − საერთო სასამართლოების დეპარტამენტი (შემდგომ − საერთო სასამართლოების დეპარტამენტი).', 'სკოლის სტრუქტურა და სკოლის სტრუქტურული ერთეულების საქმიანობის წესი განისაზღვრება სკოლის წესდებით.', 'იუსტიციის მსმენელთა საკვალიფიკაციო სიის დამტკიცების შემდეგ ამ სიაში შეყვანილ იუსტიციის მსმენელზე გაიცემა სკოლის სასწავლო კურსის დასრულების დამადასტურებელი დოკუმენტი, რომელშიც აღინიშნება, რომ მან გაიარა სკოლის სრული სასწავლო კურსი და იგი შეყვანილია იუსტიციის მსმენელთა საკვალიფიკაციო სიაში.', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „საქართველოს იუსტიციის უმაღლესი საბჭოს გადაწყვეტილების გასაჩივრება“?', 'hard', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 36⁵ ადგენს, რომ მოსამართლეს უფლება აქვს, თანამდებობაზე მისი უვადოდ გამწესებაზე უარის თქმის შესახებ საქართველოს იუსტიციის უმაღლესი საბჭოს გადაწყვეტილება გაასაჩივროს უზენაესი სასამართლოს საკვალიფიკაციო პალატაში, თუ მიაჩნია, რომ:', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 36⁵', '', '2026-03-04', false, 'საერთო სასამართლოების დეპარტამენტი:', 'მოსამართლეს უფლება აქვს, თანამდებობაზე მისი უვადოდ გამწესებაზე უარის თქმის შესახებ საქართველოს იუსტიციის უმაღლესი საბჭოს გადაწყვეტილება გაასაჩივროს უზენაესი სასამართლოს საკვალიფიკაციო პალატაში, თუ მიაჩნია, რომ:', 'სკოლის საქმიანობასთან დაკავშირებული ხარჯები გათვალისწინებულია საერთო სასამართლოების ბიუჯეტში ცალკე სტრიქონით.', 'სკოლა ყოველწლიურად შეიმუშავებს და ახორციელებს გადამზადების პროგრამებს.', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „უზენაესი სასამართლოს საკვალიფიკაციო პალატის მიერ საქმის განხილვა და გადაწყვეტილების მიღება“?', 'medium', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 36⁶ ადგენს, რომ საჩივარი ზეპირი მოსმენით განიხილება უზენაესი სასამართლოს საკვალიფიკაციო პალატის ღია სხდომაზე.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 36⁶', '', '2026-03-04', false, 'მართლმსაჯულების დაუბრკოლებლად განხორციელების, სასამართლო პრაქტიკის შესწავლისა და განზოგადების, სასამართლო სტატისტიკის ანალიზის, აგრეთვე სასამართლოს სხვა საქმიანობის უზრუნველყოფის მიზნით საქართველოს საერთო სასამართლოებში მოქმედებენ სასამართლოთა აპარატები.', 'სკოლაში პირი იუსტიციის მსმენელად კონკურსის წესით მიიღება.', 'საჩივარი ზეპირი მოსმენით განიხილება უზენაესი სასამართლოს საკვალიფიკაციო პალატის ღია სხდომაზე.', 'გადამზადება ხორციელდება სხვადასხვა სახის სემინარის, სასწავლო კურსისა და კონფერენციის, თეორიული და პრაქტიკული მეცადინეობების ჩატარების, აგრეთვე დისკუსიის მოწყობის გზით.', 'C'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „უზენაესი სასამართლოს საკვალიფიკაციო პალატის მიერ გადაწყვეტილების მიღების შედეგი“?', 'hard', 'სწორი პასუხია D, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 36⁷ ადგენს, რომ მოსამართლის თანამდებობაზე უვადოდ გამწესებაზე უარის თქმის შესახებ საქართველოს იუსტიციის უმაღლესი საბჭოს განმეორებითი გადაწყვეტილება საჩივრდება მოსამართლის თანამდებობაზე უვადოდ გამწესებაზე უარის თქმის შესახებ საქართველოს იუსტიციის უმაღლესი საბჭოს გადაწყვეტილების გასაჩივრებისათვის ამ კანონით დადგენილი წესით.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 36⁷', '', '2026-03-04', false, 'ანაზღაურებადი სტაჟირებისას პირი ინიშნება სასამართლოს აპარატის შესაბამის თანამდებობაზე.', 'სკოლაში მისაღებ კონკურსს ატარებს სკოლა.', 'გადამზადების ყოველწლიური ღონისძიებების პროგრამის გამოქვეყნების შემდეგ გადამზადების მსურველი დაგეგმილ ღონისძიებაში მონაწილეობის მისაღებად განცხადებით მიმართავს სკოლის ადმინისტრაციას.', 'მოსამართლის თანამდებობაზე უვადოდ გამწესებაზე უარის თქმის შესახებ საქართველოს იუსტიციის უმაღლესი საბჭოს განმეორებითი გადაწყვეტილება საჩივრდება მოსამართლის თანამდებობაზე უვადოდ გამწესებაზე უარის თქმის შესახებ საქართველოს იუსტიციის უმაღლესი საბჭოს გადაწყვეტილების გასაჩივრებისათვის ამ კანონით დადგენილი წესით.', 'D'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „პასუხისმგებლობა შემფასებლის საქმიანობაში უკანონო ჩარევისათვის“?', 'easy', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 36⁸ ადგენს, რომ შემფასებლის საქმიანობაში უკანონო ჩარევა დაუშვებელია და იწვევს საქართველოს სისხლის სამართლის კოდექსით გათვალისწინებულ პასუხისმგებლობას.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 36⁸', '', '2026-03-04', false, 'შემფასებლის საქმიანობაში უკანონო ჩარევა დაუშვებელია და იწვევს საქართველოს სისხლის სამართლის კოდექსით გათვალისწინებულ პასუხისმგებლობას.', 'სასამართლოში საქმეები იხილება სასამართლო სხდომის მდივნის მონაწილეობით.', 'სკოლაში მისაღები კონკურსის გამოცხადებამდე დამოუკიდებელი საბჭო დასაბუთებული გადაწყვეტილებით, სკოლის დაფინანსებისა და ინფრასტრუქტურული შესაძლებლობების გათვალისწინებით განსაზღვრავს სკოლაში მისაღებ იუსტიციის მსმენელთა საერთო რაოდენობას.', 'მოქმედი მოსამართლის კვალიფიკაციის ამაღლების პროგრამა მის საჭიროებებს უნდა შეესაბამებოდეს.', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლის სხვა სასამართლოს მოსამართლედ კონკურსის გარეშე დანიშვნის წესი“?', 'hard', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 37 ადგენს, რომ ვაკანსიის წარმოშობის შემთხვევაში შესაძლებელია თანამდებობაზე დანიშნული მოსამართლე მისივე თანხმობით კონკურსის გარეშე დაინიშნოს რაიონული (საქალაქო) ან სააპელაციო სასამართლოს მოსამართლედ.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 37', '', '2026-03-04', false, 'რაიონულ (საქალაქო), სააპელაციო და უზენაეს სასამართლოებში მოსამართლეთა შორის საქმეები ნაწილდება ავტომატურად, ელექტრონული სისტემის მეშვეობით, შემთხვევითი განაწილების პრინციპის დაცვით.', 'ვაკანსიის წარმოშობის შემთხვევაში შესაძლებელია თანამდებობაზე დანიშნული მოსამართლე მისივე თანხმობით კონკურსის გარეშე დაინიშნოს რაიონული (საქალაქო) ან სააპელაციო სასამართლოს მოსამართლედ.', 'იუსტიციის მსმენელი არის პირი, რომელიც კონკურსის გავლის შედეგად, საქართველოს იუსტიციის უმაღლესი საბჭოს გადაწყვეტილებით ჩაირიცხა სკოლაში სასწავლებლად.', 'გადამზადების კურსის ფარგლებში განსახორციელებელ ღონისძიებაში მონაწილეობისათვის პროკურორის, ადვოკატისა და სხვა პირის დაშვების წესი განისაზღვრება სკოლის წესდებით.', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „უფლებამოსილების სხვა მოსამართლისათვის დაკისრების/მოსამართლის სხვა სასამართლოში მივლინების წესი“?', 'hard', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 37¹ ადგენს, რომ ამასთანავე, ეს წესი არ გამოიყენება იმ შემთხვევაში, თუ მოსამართლე თავისი ინიციატივით მიმართავს საქართველოს იუსტიციის უმაღლეს საბჭოს მისი სხვა სასამართლოში მივლინების თაობაზე.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 37¹', '', '2026-03-04', false, 'სასამართლოების მანდატურის სამსახურების საქმიანობის საერთო ხელმძღვანელობასა და კონტროლს ახორციელებს საქართველოს იუსტიციის უმაღლესი საბჭოს შესაბამისი სტრუქტურული ერთეული.', 'იუსტიციის მსმენელი სასწავლო კურსის გავლისას იღებს სახელმწიფო სტიპენდიას, რომლის ოდენობა არ შეიძლება იყოს პირველი ინსტანციის სასამართლოს მოსამართლის მინიმალური ხელფასის 1/3-ზე ნაკლები.', 'ამასთანავე, ეს წესი არ გამოიყენება იმ შემთხვევაში, თუ მოსამართლე თავისი ინიციატივით მიმართავს საქართველოს იუსტიციის უმაღლეს საბჭოს მისი სხვა სასამართლოში მივლინების თაობაზე.', 'უცხო ქვეყნის მოსამართლეებისათვის, სასამართლო სისტემის მოხელეებისა და იურიდიული სფეროს სხვა წარმომადგენლებისათვის შესაძლებელია შეიქმნას სპეციალური სასწავლო კურსი.', 'C'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლის ფიცი“?', 'hard', 'სწორი პასუხია D, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 38 ადგენს, რომ უზენაესი სასამართლოს თავმჯდომარე და უზენაესი სასამართლოს წევრები ფიცს დებენ საქართველოს პარლამენტის წინაშე, ხოლო სააპელაციო და რაიონული (საქალაქო) სასამართლოების მოსამართლეები – საქართველოს იუსტიციის უმაღლესი საბჭოს წინაშე.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 38', '', '2026-03-04', false, 'სასამართლოს მანდატურის სამსახურის უფროსს თანამდებობაზე ნიშნავს და თანამდებობიდან ათავისუფლებს შესაბამისად სასამართლოს თავმჯდომარე ან საქართველოს იუსტიციის უმაღლესი საბჭოს მდივანი.', 'იუსტიციის მსმენელი ვალდებულია დაიცვას დისციპლინური ნორმები.', 'სკოლას უფლება აქვს, გასცეს სასწავლო გრანტი მხოლოდ მოსამართლესა და სასამართლოს მოხელეზე, მათი კვალიფიკაციის ამაღლების მიზნით.', 'უზენაესი სასამართლოს თავმჯდომარე და უზენაესი სასამართლოს წევრები ფიცს დებენ საქართველოს პარლამენტის წინაშე, ხოლო სააპელაციო და რაიონული (საქალაქო) სასამართლოების მოსამართლეები – საქართველოს იუსტიციის უმაღლესი საბჭოს წინაშე.', 'D'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლის თანამდებობრივი შეუთავსებლობა“?', 'medium', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 39 ადგენს, რომ მოსამართლის თანამდებობა შეუთავსებელია ნებისმიერ სხვა თანამდებობასთან და ანაზღაურებად საქმიანობასთან, გარდა საქართველოს კონსტიტუციით დადგენილი გამონაკლისისა.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 39', '', '2026-03-04', false, 'მოსამართლის თანამდებობა შეუთავსებელია ნებისმიერ სხვა თანამდებობასთან და ანაზღაურებად საქმიანობასთან, გარდა საქართველოს კონსტიტუციით დადგენილი გამონაკლისისა.', 'უზრუნველყოფს მოსამართლეების, სასამართლო პროცესის მონაწილეებისა და მოწმეების უსაფრთხოებას;', 'იუსტიციის მსმენელს სკოლაში სწავლის პერიოდი სპეციალობით მუშაობის სტაჟში ჩაეთვლება.', 'სკოლის ბაზაზე სასამართლო სისტემის გამოწვევების ანალიზისა და კვლევისათვის შესაძლებელია შეიქმნას კვლევითი ინსტიტუტები.', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლის ხელშეუხებლობა“?', 'hard', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 40 ადგენს, რომ დაუშვებელია მისი სისხლის სამართლის პასუხისგებაში მიცემა, დაკავება ან დაპატიმრება, საცხოვრებელი ან სამუშაო ადგილის, მანქანის ან პირადი გაჩხრეკა საქართველოს იუსტიციის უმაღლესი საბჭოს თანხმობის გარეშე.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 40', '', '2026-03-04', false, 'სასამართლოს მანდატურს ფიზიკური ძალის, სპეციალური საშუალებებისა და იარაღის გამოყენების უფლება აქვს მხოლოდ იმ შემთხვევაში, როდესაც სხვა, შედარებით მსუბუქი ზომების გამოყენებით შეუძლებელია მისი სამსახურებრივი მოვალეობების შესრულება.', 'დაუშვებელია მისი სისხლის სამართლის პასუხისგებაში მიცემა, დაკავება ან დაპატიმრება, საცხოვრებელი ან სამუშაო ადგილის, მანქანის ან პირადი გაჩხრეკა საქართველოს იუსტიციის უმაღლესი საბჭოს თანხმობის გარეშე.', 'იუსტიციის მსმენელს უფლება აქვს, გაეცნოს მის შესახებ სკოლაში არსებულ ნებისმიერ ინფორმაციასა და ოფიციალურ დოკუმენტს და მიიღოს მათი ასლები.', 'პირი, რომელმაც გაიარა სკოლის სრული სასწავლო კურსი და შეყვანილია იუსტიციის მსმენელთა საკვალიფიკაციო სიაში, მოსამართლის თანამდებობის დასაკავებლად თავისუფლდება სკოლაში სწავლისგან, მიუხედავად იმისა, რა ვადით ეკავა მას მოსამართლის თანამდებობა ან სკოლის დამთავრების შემდეგ დაინიშნა თუ არა იგი ამ თანამდებობაზე.', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლის დაწინაურება“?', 'easy', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 41 ადგენს, რომ რაიონული (საქალაქო) სასამართლოს მოსამართლე შეიძლება დაინიშნოს სააპელაციო სასამართლოში, თუ იგი რაიონულ (საქალაქო) სასამართლოში მოსამართლის უფლებამოსილებას ახორციელებდა არანაკლებ 3 წლის განმავლობაში.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 41', '', '2026-03-04', false, 'საქართველოს მოსამართლეთა კონფერენცია არის საქართველოს საერთო სასამართლოების მოსამართლეთა თვითმმართველობის ორგანო.', 'სკოლაში სწავლების ხანგრძლივობაა 16 თვე.', 'რაიონული (საქალაქო) სასამართლოს მოსამართლე შეიძლება დაინიშნოს სააპელაციო სასამართლოში, თუ იგი რაიონულ (საქალაქო) სასამართლოში მოსამართლის უფლებამოსილებას ახორციელებდა არანაკლებ 3 წლის განმავლობაში.', 'საერთო სასამართლოების დაფინანსება ხორციელდება საქართველოს სახელმწიფო ბიუჯეტის სახსრებით.', 'C'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლის თანამდებობიდან გათავისუფლება“?', 'hard', 'სწორი პასუხია D, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 42 ადგენს, რომ უზენაესი სასამართლოს თავმჯდომარისა და უზენაესი სასამართლოს მოსამართლის თანამდებობიდან გადაყენება შეიძლება მხოლოდ იმპიჩმენტის წესით.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 42', '', '2026-03-04', false, 'საქართველოს მოსამართლეთა კონფერენციის სისტემაში, ამ კანონის 63-ე მუხლით განსაზღვრული ფუნქციების შესრულების ხელშეწყობის მიზნით, იქმნება ადმინისტრაციული კომიტეტი.', 'იუსტიციის მსმენელის მომზადების სასწავლო პროგრამამ უნდა უზრუნველყოს ამ კანონის 35​1 მუხლით გათვალისწინებული კრიტერიუმების შესაბამისი თეორიული ცოდნის გაღრმავება, პრაქტიკული უნარებისა და თვისებების განვითარება.', 'მოსამართლის სამართლებრივი და სოციალური დაცვის გარანტიები განისაზღვრება საქართველოს კონსტიტუციით, ამ კანონითა და საქართველოს კანონმდებლობით.', 'უზენაესი სასამართლოს თავმჯდომარისა და უზენაესი სასამართლოს მოსამართლის თანამდებობიდან გადაყენება შეიძლება მხოლოდ იმპიჩმენტის წესით.', 'D'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლის თანამდებობიდან გათავისუფლების, უზენაესი სასამართლოს თავმჯდომარისა და უზენაესი სასამართლოს წევრის უფლებამოსილების შეწყვეტის საფუძვლები“?', 'medium', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 43 ადგენს, რომ მოსამართლის თანამდებობიდან გათავისუფლების, უზენაესი სასამართლოს თავმჯდომარისა და უზენაესი სასამართლოს წევრის უფლებამოსილების შეწყვეტის საფუძვლებია:', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 43', '', '2026-03-04', false, 'მოსამართლის თანამდებობიდან გათავისუფლების, უზენაესი სასამართლოს თავმჯდომარისა და უზენაესი სასამართლოს წევრის უფლებამოსილების შეწყვეტის საფუძვლებია:', 'საქართველოს მოსამართლეთა კონფერენცია:', 'სკოლაში სწავლების ფორმებია: სემინარი, სასამართლო პროცესის სიმულაცია, დისკუსია, სწავლება სასამართლო გადაწყვეტილების მიღებისა და მისი დასაბუთების საკითხებზე, საღამოს სწავლება, დისტანციური სწავლება, აგრეთვე სხვა ფორმები, რომლებსაც სკოლის დირექტორის წარდგინებით ამტკიცებს დამოუკიდებელი საბჭო.', 'მოსამართლის შრომის ანაზღაურება შედგება თანამდებობრივი სარგოსგან და დანამატისგან.', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლის სხვა სასამართლო თანამდებობაზე გამწესება და თანამდებობიდან მისი გათავისუფლება სასამართლოს ლიკვიდაციის და მოსამართლის თანამდებობის შემცირების დროს“?', 'hard', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 44 ადგენს, რომ სასამართლოს ლიკვიდაციის, აგრეთვე მოსამართლის თანამდებობის შემცირების შემთხვევაში მოსამართლეს მისივე წინასწარი წერილობითი თანხმობით, საქართველოს კანონმდებლობით დადგენილი წესით შეიძლება დაეკისროს შესაბამისი ან ქვემდგომი ინსტანციის სასამართლოს მოსამართლის უფლებამოსილების განხორციელება.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 44', '', '2026-03-04', false, 'საქართველოს მოსამართლეთა კონფერენცია, როგორც წესი, მოიწვევა წელიწადში ერთხელ.', 'სასამართლოს ლიკვიდაციის, აგრეთვე მოსამართლის თანამდებობის შემცირების შემთხვევაში მოსამართლეს მისივე წინასწარი წერილობითი თანხმობით, საქართველოს კანონმდებლობით დადგენილი წესით შეიძლება დაეკისროს შესაბამისი ან ქვემდგომი ინსტანციის სასამართლოს მოსამართლის უფლებამოსილების განხორციელება.', 'სკოლაში იუსტიციის მსმენელთა სწავლებას წარმართავენ სკოლის მასწავლებლები.', 'უზენაესი სასამართლოს მოსამართლეს უფლებამოსილების ვადის ამოწურვისას ან საპენსიო ასაკის მიღწევისას ენიშნება სახელმწიფო კომპენსაცია 1200 ლარის ოდენობით.', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლის ჩამოცილება საქმეთა განხილვისგან“?', 'hard', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 45 ადგენს, რომ საქართველოს საერთო სასამართლოების მოსამართლეთა სადისციპლინო კოლეგია საქართველოს იუსტიციის უმაღლესი საბჭოს წარდგინებას იხილავს მისი მიღებიდან 10 სამუშაო დღის ვადაში, ამ კანონით დადგენილი საერთო წესით.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 45', '', '2026-03-04', false, 'იუსტიციის უმაღლესი სკოლა (შემდგომ – სკოლა), როგორც საჯარო სამართლის იურიდიული პირი, იქმნება ამ კანონის საფუძველზე.', 'სკოლაში თეორიული კურსის დასასრულს იუსტიციის მსმენელი აბარებს გამოცდას, რომლის მიზანია სკოლაში სწავლის პერიოდში მიღებული თეორიული ცოდნის შეფასება.', 'საქართველოს საერთო სასამართლოების მოსამართლეთა სადისციპლინო კოლეგია საქართველოს იუსტიციის უმაღლესი საბჭოს წარდგინებას იხილავს მისი მიღებიდან 10 სამუშაო დღის ვადაში, ამ კანონით დადგენილი საერთო წესით.', 'სამსახურებრივი მოვალეობის შესრულებისას, რაც უკავშირდება მისი სამოსამართლო უფლებამოსილების განხორციელებას, მოსამართლის დაღუპვის შემთხვევაში მის ოჯახს საქართველოს სახელმწიფო ბიუჯეტიდან ეძლევა ერთდროული კომპენსაცია 25 000 ლარის ოდენობით.', 'C'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „საქართველოს იუსტიციის უმაღლესი საბჭო“?', 'medium', 'სწორი პასუხია D, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 47 ადგენს, რომ საქართველოს იუსტიციის უმაღლესი საბჭო ანგარიშვალდებულია საქართველოს მოსამართლეთა კონფერენციის წინაშე.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 47', '', '2026-03-04', false, 'სკოლის მართვის ორგანოებია: სკოლის დამოუკიდებელი საბჭო და სკოლის დირექცია.', 'თეორიული კურსის დამამთავრებელი გამოცდის ჩაბარების შემდეგ იუსტიციის მსმენელი გადის სტაჟირებას.', 'მოსამართლის სიცოცხლისა და ჯანმრთელობის დაზღვევა სავალდებულოა.', 'საქართველოს იუსტიციის უმაღლესი საბჭო ანგარიშვალდებულია საქართველოს მოსამართლეთა კონფერენციის წინაშე.', 'D'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „საქართველოს იუსტიციის უმაღლესი საბჭოს წევრის უფლებამოსილების შეწყვეტის საფუძვლები“?', 'easy', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 48 ადგენს, რომ საქართველოს იუსტიციის უმაღლესი საბჭოს წევრის უფლებამოსილების შეწყვეტის საფუძვლებია:', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 48', '', '2026-03-04', false, 'საქართველოს იუსტიციის უმაღლესი საბჭოს წევრის უფლებამოსილების შეწყვეტის საფუძვლებია:', 'სკოლის საქმიანობის მიმართულებებს განსაზღვრავს, კოორდინაციას უწევს და მათ აღსრულებას ზედამხედველობს სკოლის დამოუკიდებელი საბჭო (შემდგომ – დამოუკიდებელი საბჭო).', 'სკოლის დირექტორი სტაჟირების ხელმძღვანელის წარდგინებით ამ კანონის 66​26 მუხლის მე-2 პუნქტით განსაზღვრულ ორგანოებში ნიშნავს სტაჟირების კოორდინატორებს.', 'ამ თავით გათვალისწინებული პასუხისმგებლობა არ დგება იმ ქმედებისთვის, რომელიც შეიცავს საქართველოს სისხლის სამართლის კოდექსით გათვალისწინებული დანაშაულის ნიშნებს.', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „საქართველოს იუსტიციის უმაღლესი საბჭოს უფლებამოსილება“?', 'medium', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 49 ადგენს, რომ საქართველოს იუსტიციის უმაღლესი საბჭო:', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 49', '', '2026-03-04', false, 'დამოუკიდებელი საბჭოს წევრის თავისი უფლებამოსილების განხორციელებისგან გათავისუფლების საფუძვლებია:', 'საქართველოს იუსტიციის უმაღლესი საბჭო:', 'სტაჟირების დასასრულს იუსტიციის მსმენელი ადგენს თავის მიერ გაწეული საქმიანობის შესახებ წერილობით ანგარიშს, აგრეთვე ასრულებს ნაშრომს სტაჟირების ორგანოს ფუნქციონირების, ამ ორგანოში არსებული პრობლემებისა და მათი გადაჭრის გზების თაობაზე.', 'თუ კომუნიკაცია სასამართლოს თავმჯდომარესთან განხორციელდა, სასამართლოს თავმჯდომარე ამის შესახებ დაუყოვნებლივ, წერილობით ატყობინებს ზემდგომი ინსტანციის სასამართლოს თავმჯდომარეს ან მის მიერ უფლებამოსილ მოსამართლეს.', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლის მიერ სამეცნიერო ან პედაგოგიური საქმიანობის განხორციელებაზე, აგრეთვე მოსამართლის მიერ „კორუფციის წინააღმდეგ ბრძოლის შესახებ“ საქართველოს კანონით გათვალისწინებული და ნებადართული სარგებლის მიღებაზე თანხმობის გაცემის წესი“?', 'hard', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 49¹ ადგენს, რომ შეტყობინება გულისხმობს საქართველოს იუსტიციის უმაღლესი საბჭოსთვის სამეცნიერო ან პედაგოგიური საქმიანობის ან „კორუფციის წინააღმდეგ ბრძოლის შესახებ“ საქართველოს კანონით გათვალისწინებული და ნებადართული სარგებლის თაობაზე შემდეგი ინფორმაციის წარდგენას:', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 49¹', '', '2026-03-04', false, 'დამოუკიდებელი საბჭოს სხდომა, როგორც წესი, მოიწვევა არანაკლებ წელიწადში ერთხელ.', 'სკოლა სტაჟირების დასასრულს იუსტიციის მსმენელთათვის ატარებს სემინარებს, რომელთა მიზანია მათ მიერ თეორიული კურსისა და სტაჟირების გავლის დროს მიღებული ცოდნისა და გამოცდილების განზოგადება, აგრეთვე იუსტიციის მსმენელების სკოლის დამამთავრებელი გამოცდისათვის მომზადება.', 'შეტყობინება გულისხმობს საქართველოს იუსტიციის უმაღლესი საბჭოსთვის სამეცნიერო ან პედაგოგიური საქმიანობის ან „კორუფციის წინააღმდეგ ბრძოლის შესახებ“ საქართველოს კანონით გათვალისწინებული და ნებადართული სარგებლის თაობაზე შემდეგი ინფორმაციის წარდგენას:', 'პროკურატურის თანამშრომლის მიერ ამ კანონის 72 ​1 მუხლით განსაზღვრული მოთხოვნის დარღვევა განიხილება პროკურატურის თანამშრომლისათვის შეუფერებელ საქციელად და გამოიწვევს „პროკურატურის შესახებ“ საქართველოს ორგანული კანონით გათვალისწინებულ დისციპლინურ პასუხისმგებლობას და დაჯარიმებას ამ თავით დადგენილი წესით.', 'C'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „საქართველოს იუსტიციის უმაღლესი საბჭოს მიერ საკითხის გადაწყვეტის წესი“?', 'medium', 'სწორი პასუხია D, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 50 ადგენს, რომ საქართველოს იუსტიციის უმაღლესი საბჭო უფლებამოსილია განიხილოს საკითხი და მიიღოს გადაწყვეტილება, თუ მის სხდომას ესწრება საბჭოს წევრთა ნახევარზე მეტი.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 50', '', '2026-03-04', false, 'სკოლის დირექცია შედგება სკოლის დირექტორისგან, მისი მოადგილეებისა და სტაჟირების ხელმძღვანელისგან.', 'სკოლაში სწავლის დასასრულს იუსტიციის მსმენელი აბარებს სკოლის დამამთავრებელ გამოცდას, რომლის დანიშნულებაა იუსტიციის მსმენელის მიერ მიღებული თეორიული ცოდნისა და პრაქტიკული გამოცდილების შეფასება.', 'ადვოკატის მიერ ამ კანონის 72 ​1 მუხლით განსაზღვრული მოთხოვნის დარღვევა განიხილება ადვოკატთა პროფესიული ეთიკის ნორმების დარღვევად და გამოიწვევს „ადვოკატთა შესახებ“ საქართველოს კანონით გათვალისწინებული დისციპლინური პასუხისმგებლობის დაკისრებას და ამ თავით დადგენილი წესით დაჯარიმებას.', 'საქართველოს იუსტიციის უმაღლესი საბჭო უფლებამოსილია განიხილოს საკითხი და მიიღოს გადაწყვეტილება, თუ მის სხდომას ესწრება საბჭოს წევრთა ნახევარზე მეტი.', 'D'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „საქართველოს იუსტიციის უმაღლესი საბჭოს მდივანი“?', 'medium', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 51 ადგენს, რომ საქართველოს იუსტიციის უმაღლესი საბჭოს მდივანს 4 წლის ვადით ირჩევს საქართველოს მოსამართლეთა კონფერენცია მის მიერ არჩეულ საქართველოს იუსტიციის უმაღლესი საბჭოს წევრთაგან.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 51', '', '2026-03-04', false, 'საქართველოს იუსტიციის უმაღლესი საბჭოს მდივანს 4 წლის ვადით ირჩევს საქართველოს მოსამართლეთა კონფერენცია მის მიერ არჩეულ საქართველოს იუსტიციის უმაღლესი საბჭოს წევრთაგან.', 'წარმოადგენს სკოლას; უზრუნველყოფს სკოლის ფუნქციონირებას, იუსტიციის მსმენელთა სასწავლო კურსისა და გადამზადების კურსის წარმართვას;', 'სკოლის დამამთავრებელი გამოცდის დასრულებიდან 1 თვის ვადაში სკოლის დირექტორი დამოუკიდებელ საბჭოს დასამტკიცებლად წარუდგენს იუსტიციის მსმენელთა საკვალიფიკაციო სიას.', 'გამომძიებლის მიერ ამ კანონის 72 ​1 მუხლით განსაზღვრული მოთხოვნის დარღვევა გამოიწვევს საქართველოს კანონმდებლობით გათვალისწინებული დისციპლინური პასუხისმგებლობის დაკისრებას და ამ თავით დადგენილი წესით დაჯარიმებას.', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „საკვალიფიკაციო საგამოცდო კომისია“?', 'hard', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 52 ადგენს, რომ მოსამართლეობის საკვალიფიკაციო გამოცდის ორგანიზებისა და ჩატარების მიზნით საქართველოს იუსტიციის უმაღლესი საბჭო თავისი რეგლამენტით დადგენილი წესით ქმნის საკვალიფიკაციო საგამოცდო კომისიას და ამტკიცებს საკვალიფიკაციო საგამოცდო კომისიის შემადგენლობასა და დებულებას.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 52', '', '2026-03-04', false, 'სკოლის დირექტორის მოადგილე უზრუნველყოფს სასწავლო და გადამზადების პროგრამების განხორციელებას.', 'მოსამართლეობის საკვალიფიკაციო გამოცდის ორგანიზებისა და ჩატარების მიზნით საქართველოს იუსტიციის უმაღლესი საბჭო თავისი რეგლამენტით დადგენილი წესით ქმნის საკვალიფიკაციო საგამოცდო კომისიას და ამტკიცებს საკვალიფიკაციო საგამოცდო კომისიის შემადგენლობასა და დებულებას.', 'საკვალიფიკაციო სიის შედგენის დროს კოეფიციენტით ჯამდება იუსტიციის მსმენელის მიერ:', 'პროცესის მონაწილის, დაინტერესებული პირის, საჯარო მოსამსახურის ან ნებისმიერი სხვა პირის მიერ ამ თავით განსაზღვრული მოთხოვნის დარღვევა −', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლეობის საკვალიფიკაციო გამოცდა“?', 'easy', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 53 ადგენს, რომ მოსამართლეობის საკვალიფიკაციო გამოცდის ჩაბარების უფლება აქვს 25 წლის ასაკს მიღწეულ, უმაღლესი იურიდიული განათლების მქონე საქართველოს ყველა მოქალაქეს.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 53', '', '2026-03-04', false, 'სკოლის დირექტორის, სკოლის დირექტორის მოადგილის, სტაჟირების ხელმძღვანელის თანამდებობიდან გათავისუფლების საფუძვლებია:', 'მოსამართლეობის კანდიდატის შერჩევისას გაითვალისწინება იუსტიციის მსმენელის რიგითი ნომერი იუსტიციის მსმენელთა საკვალიფიკაციო სიაში, აგრეთვე დამოუკიდებელი საბჭოს შეფასება.', 'მოსამართლეობის საკვალიფიკაციო გამოცდის ჩაბარების უფლება აქვს 25 წლის ასაკს მიღწეულ, უმაღლესი იურიდიული განათლების მქონე საქართველოს ყველა მოქალაქეს.', 'მოსამართლესთან ამ კანონის 72​1 მუხლის პირველი პუნქტით გათვალისწინებული კომუნიკაციის თაობაზე წერილობითი შეტყობინების განხილვის უფლებამოსილების მქონე მოსამართლეს შეუძლია ჩაატაროს ზეპირი მოსმენა მხარეთა მონაწილეობით.', 'C'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „საერთო სასამართლოების დეპარტამენტი“?', 'hard', 'სწორი პასუხია D, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 54 ადგენს, რომ საქართველოს საერთო სასამართლოების მატერიალურ-ტექნიკურ უზრუნველყოფას ახორციელებს საქართველოს იუსტიციის უმაღლეს საბჭოსთან არსებული საჯარო სამართლის იურიდიული პირი − საერთო სასამართლოების დეპარტამენტი (შემდგომ − საერთო სასამართლოების დეპარტამენტი).', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 54', '', '2026-03-04', false, 'სკოლის სტრუქტურა და სკოლის სტრუქტურული ერთეულების საქმიანობის წესი განისაზღვრება სკოლის წესდებით.', 'იუსტიციის მსმენელთა საკვალიფიკაციო სიის დამტკიცების შემდეგ ამ სიაში შეყვანილ იუსტიციის მსმენელზე გაიცემა სკოლის სასწავლო კურსის დასრულების დამადასტურებელი დოკუმენტი, რომელშიც აღინიშნება, რომ მან გაიარა სკოლის სრული სასწავლო კურსი და იგი შეყვანილია იუსტიციის მსმენელთა საკვალიფიკაციო სიაში.', 'პროკურატურის თანამშრომლის მიერ ამ თავის მოთხოვნათა დარღვევის შემთხვევაში საქართველოს იუსტიციის უმაღლესი საბჭოს მდივანი რეაგირების მიზნით წარდგინებით მიმართავს და შესაბამის მასალებს უგზავნის საქართველოს გენერალურ პროკურორს.', 'საქართველოს საერთო სასამართლოების მატერიალურ-ტექნიკურ უზრუნველყოფას ახორციელებს საქართველოს იუსტიციის უმაღლეს საბჭოსთან არსებული საჯარო სამართლის იურიდიული პირი − საერთო სასამართლოების დეპარტამენტი (შემდგომ − საერთო სასამართლოების დეპარტამენტი).', 'D'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „საერთო სასამართლოების დეპარტამენტის უფლებამოსილება“?', 'medium', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 55 ადგენს, რომ საერთო სასამართლოების დეპარტამენტი:', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 55', '', '2026-03-04', false, 'საერთო სასამართლოების დეპარტამენტი:', 'სკოლის საქმიანობასთან დაკავშირებული ხარჯები გათვალისწინებულია საერთო სასამართლოების ბიუჯეტში ცალკე სტრიქონით.', 'სკოლა ყოველწლიურად შეიმუშავებს და ახორციელებს გადამზადების პროგრამებს.', 'საჩივრის განხილვისას საჩივრის განმხილველი პირი ამოწმებს, დაჯარიმების შესახებ განკარგულების გამოტანისას დაიცვა თუ არა მოსამართლესთან კომუნიკაციის თაობაზე წერილობითი შეტყობინების განხილვის უფლებამოსილების მქონე მოსამართლემ ამ კანონის 72​8 მუხლით განსაზღვრული მოთხოვნები.', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „სასამართლოს აპარატი, სასამართლოს მენეჯერი“?', 'hard', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 56 ადგენს, რომ მართლმსაჯულების დაუბრკოლებლად განხორციელების, სასამართლო პრაქტიკის შესწავლისა და განზოგადების, სასამართლო სტატისტიკის ანალიზის, აგრეთვე სასამართლოს სხვა საქმიანობის უზრუნველყოფის მიზნით საქართველოს საერთო სასამართლოებში მოქმედებენ სასამართლოთა აპარატები.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 56', '', '2026-03-04', false, 'სკოლაში პირი იუსტიციის მსმენელად კონკურსის წესით მიიღება.', 'მართლმსაჯულების დაუბრკოლებლად განხორციელების, სასამართლო პრაქტიკის შესწავლისა და განზოგადების, სასამართლო სტატისტიკის ანალიზის, აგრეთვე სასამართლოს სხვა საქმიანობის უზრუნველყოფის მიზნით საქართველოს საერთო სასამართლოებში მოქმედებენ სასამართლოთა აპარატები.', 'გადამზადება ხორციელდება სხვადასხვა სახის სემინარის, სასწავლო კურსისა და კონფერენციის, თეორიული და პრაქტიკული მეცადინეობების ჩატარების, აგრეთვე დისკუსიის მოწყობის გზით.', 'მოსამართლესთან ამ კანონის 72​1 მუხლის პირველი პუნქტით გათვალისწინებული კომუნიკაციის თაობაზე ინფორმაცია საჯაროა, გარდა ინფორმაციისა იმ მოსამართლის ვინაობის შესახებ, რომელთანაც განხორციელდა კომუნიკაცია, და ინფორმაციისა იმ საქმის შესახებ, რომლის თაობაზედაც განხორციელდა კომუნიკაცია.', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოთხოვნები, რომლებიც წაეყენება სასამართლოს აპარატის თანამშრომელ ს თანამდებობაზე დანიშვნისას“?', 'hard', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 57 ადგენს, რომ ანაზღაურებადი სტაჟირებისას პირი ინიშნება სასამართლოს აპარატის შესაბამის თანამდებობაზე.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 57', '', '2026-03-04', false, 'სკოლაში მისაღებ კონკურსს ატარებს სკოლა.', 'გადამზადების ყოველწლიური ღონისძიებების პროგრამის გამოქვეყნების შემდეგ გადამზადების მსურველი დაგეგმილ ღონისძიებაში მონაწილეობის მისაღებად განცხადებით მიმართავს სკოლის ადმინისტრაციას.', 'ანაზღაურებადი სტაჟირებისას პირი ინიშნება სასამართლოს აპარატის შესაბამის თანამდებობაზე.', 'ამ მუხლში გამოყენებულ ტერმინებს აქვს შემდეგი მნიშვნელობა:', 'C'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლის თანაშემწე და სასამართლო სხდომის მდივანი“?', 'medium', 'სწორი პასუხია D, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 58 ადგენს, რომ სასამართლოში საქმეები იხილება სასამართლო სხდომის მდივნის მონაწილეობით.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 58', '', '2026-03-04', false, 'სკოლაში მისაღები კონკურსის გამოცხადებამდე დამოუკიდებელი საბჭო დასაბუთებული გადაწყვეტილებით, სკოლის დაფინანსებისა და ინფრასტრუქტურული შესაძლებლობების გათვალისწინებით განსაზღვრავს სკოლაში მისაღებ იუსტიციის მსმენელთა საერთო რაოდენობას.', 'მოქმედი მოსამართლის კვალიფიკაციის ამაღლების პროგრამა მის საჭიროებებს უნდა შეესაბამებოდეს.', 'უზენაესი სასამართლოს ადგილსამყოფელია საქართველოს მართლმსაჯულების სასახლე ქალაქ თბილისში.', 'სასამართლოში საქმეები იხილება სასამართლო სხდომის მდივნის მონაწილეობით.', 'D'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „მოსამართლეთა შორის საქმეების განაწილება“?', 'easy', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 58¹ ადგენს, რომ რაიონულ (საქალაქო), სააპელაციო და უზენაეს სასამართლოებში მოსამართლეთა შორის საქმეები ნაწილდება ავტომატურად, ელექტრონული სისტემის მეშვეობით, შემთხვევითი განაწილების პრინციპის დაცვით.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 58¹', '', '2026-03-04', false, 'რაიონულ (საქალაქო), სააპელაციო და უზენაეს სასამართლოებში მოსამართლეთა შორის საქმეები ნაწილდება ავტომატურად, ელექტრონული სისტემის მეშვეობით, შემთხვევითი განაწილების პრინციპის დაცვით.', 'იუსტიციის მსმენელი არის პირი, რომელიც კონკურსის გავლის შედეგად, საქართველოს იუსტიციის უმაღლესი საბჭოს გადაწყვეტილებით ჩაირიცხა სკოლაში სასწავლებლად.', 'გადამზადების კურსის ფარგლებში განსახორციელებელ ღონისძიებაში მონაწილეობისათვის პროკურორის, ადვოკატისა და სხვა პირის დაშვების წესი განისაზღვრება სკოლის წესდებით.', 'სასამართლო ხელისუფლების სიმბოლოებია მოსამართლის თანამდებობრივი განმასხვავებელი ნიშნები, რომლებსაც შეიმუშავებს და ამტკიცებს საქართველოს იუსტიციის უმაღლესი საბჭო.', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „სასამართლოს მანდატური, სასამართლოს მანდატურის სამსახური“?', 'medium', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 59 ადგენს, რომ სასამართლოების მანდატურის სამსახურების საქმიანობის საერთო ხელმძღვანელობასა და კონტროლს ახორციელებს საქართველოს იუსტიციის უმაღლესი საბჭოს შესაბამისი სტრუქტურული ერთეული.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 59', '', '2026-03-04', false, 'იუსტიციის მსმენელი სასწავლო კურსის გავლისას იღებს სახელმწიფო სტიპენდიას, რომლის ოდენობა არ შეიძლება იყოს პირველი ინსტანციის სასამართლოს მოსამართლის მინიმალური ხელფასის 1/3-ზე ნაკლები.', 'სასამართლოების მანდატურის სამსახურების საქმიანობის საერთო ხელმძღვანელობასა და კონტროლს ახორციელებს საქართველოს იუსტიციის უმაღლესი საბჭოს შესაბამისი სტრუქტურული ერთეული.', 'უცხო ქვეყნის მოსამართლეებისათვის, სასამართლო სისტემის მოხელეებისა და იურიდიული სფეროს სხვა წარმომადგენლებისათვის შესაძლებელია შეიქმნას სპეციალური სასწავლო კურსი.', 'სასამართლოს ბეჭედზე გამოსახულია საქართველოს სახელმწიფო გერბი და სასამართლოს დასახელება.', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „სასამართლოს მანდატურის სამსახურის უფროსი“?', 'hard', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 60 ადგენს, რომ სასამართლოს მანდატურის სამსახურის უფროსს თანამდებობაზე ნიშნავს და თანამდებობიდან ათავისუფლებს შესაბამისად სასამართლოს თავმჯდომარე ან საქართველოს იუსტიციის უმაღლესი საბჭოს მდივანი.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 60', '', '2026-03-04', false, 'იუსტიციის მსმენელი ვალდებულია დაიცვას დისციპლინური ნორმები.', 'სკოლას უფლება აქვს, გასცეს სასწავლო გრანტი მხოლოდ მოსამართლესა და სასამართლოს მოხელეზე, მათი კვალიფიკაციის ამაღლების მიზნით.', 'სასამართლოს მანდატურის სამსახურის უფროსს თანამდებობაზე ნიშნავს და თანამდებობიდან ათავისუფლებს შესაბამისად სასამართლოს თავმჯდომარე ან საქართველოს იუსტიციის უმაღლესი საბჭოს მდივანი.', 'მოსამართლეს დისციპლინური პასუხისმგებლობა (სახდელი) დაეკისრება მხოლოდ იმ შემთხვევაში, თუ ამ თავით დადგენილი წესით განხორციელებული დისციპლინური სამართალწარმოების შედეგად დადგინდება მოსამართლის მიერ დისციპლინური გადაცდომის ჩადენა.', 'C'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „სასამართლოს მანდატურის უფლება-მოვალეობანი“?', 'hard', 'სწორი პასუხია D, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 61 ადგენს, რომ უზრუნველყოფს მოსამართლეების, სასამართლო პროცესის მონაწილეებისა და მოწმეების უსაფრთხოებას;', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 61', '', '2026-03-04', false, 'იუსტიციის მსმენელს სკოლაში სწავლის პერიოდი სპეციალობით მუშაობის სტაჟში ჩაეთვლება.', 'სკოლის ბაზაზე სასამართლო სისტემის გამოწვევების ანალიზისა და კვლევისათვის შესაძლებელია შეიქმნას კვლევითი ინსტიტუტები.', 'მოსამართლეს დისციპლინური პასუხისმგებლობა არ დაეკისრება, თუ მის მიერ დისციპლინური გადაცდომის ჩადენის დღიდან ამ გადაცდომაზე დისციპლინური სამართალწარმოების დაწყებამდე გასულია 3 წელი, ხოლო მოსამართლის დისციპლინურ პასუხისგებაში მიცემის შესახებ გადაწყვეტილების მიღების დღიდან – 1 წელი.', 'უზრუნველყოფს მოსამართლეების, სასამართლო პროცესის მონაწილეებისა და მოწმეების უსაფრთხოებას;', 'D'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „სასამართლოს მანდატურის მიერ ფიზიკური ძალის, სპეციალური საშუალებებისა და იარაღის გამოყენების შემთხვევები და წესი“?', 'hard', 'სწორი პასუხია A, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 62 ადგენს, რომ სასამართლოს მანდატურს ფიზიკური ძალის, სპეციალური საშუალებებისა და იარაღის გამოყენების უფლება აქვს მხოლოდ იმ შემთხვევაში, როდესაც სხვა, შედარებით მსუბუქი ზომების გამოყენებით შეუძლებელია მისი სამსახურებრივი მოვალეობების შესრულება.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 62', '', '2026-03-04', false, 'სასამართლოს მანდატურს ფიზიკური ძალის, სპეციალური საშუალებებისა და იარაღის გამოყენების უფლება აქვს მხოლოდ იმ შემთხვევაში, როდესაც სხვა, შედარებით მსუბუქი ზომების გამოყენებით შეუძლებელია მისი სამსახურებრივი მოვალეობების შესრულება.', 'იუსტიციის მსმენელს უფლება აქვს, გაეცნოს მის შესახებ სკოლაში არსებულ ნებისმიერ ინფორმაციასა და ოფიციალურ დოკუმენტს და მიიღოს მათი ასლები.', 'პირი, რომელმაც გაიარა სკოლის სრული სასწავლო კურსი და შეყვანილია იუსტიციის მსმენელთა საკვალიფიკაციო სიაში, მოსამართლის თანამდებობის დასაკავებლად თავისუფლდება სკოლაში სწავლისგან, მიუხედავად იმისა, რა ვადით ეკავა მას მოსამართლის თანამდებობა ან სკოლის დამთავრების შემდეგ დაინიშნა თუ არა იგი ამ თანამდებობაზე.', 'ხელფასის 10 პროცენტიდან 50 პროცენტამდე დაქვითვა არაუმეტეს 1 წლის განმავლობაში;', 'A'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „საქართველოს მოსამართლეთა კონფერენცია“?', 'medium', 'სწორი პასუხია B, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 63 ადგენს, რომ საქართველოს მოსამართლეთა კონფერენცია არის საქართველოს საერთო სასამართლოების მოსამართლეთა თვითმმართველობის ორგანო.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 63', '', '2026-03-04', false, 'სკოლაში სწავლების ხანგრძლივობაა 16 თვე.', 'საქართველოს მოსამართლეთა კონფერენცია არის საქართველოს საერთო სასამართლოების მოსამართლეთა თვითმმართველობის ორგანო.', 'საერთო სასამართლოების დაფინანსება ხორციელდება საქართველოს სახელმწიფო ბიუჯეტის სახსრებით.', 'დისციპლინური სამართალწარმოების პროცესი კონფიდენციალურია.', 'B'),
    ('constitutional', 'common-courts', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“-ის მიხედვით, რომელი დებულება შეესაბამება საკითხს: „საქართველოს მოსამართლეთა კონფერენციის ორგანიზაციული სტრუქტურა“?', 'easy', 'სწორი პასუხია C, რადგან საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“ მუხლი 64 ადგენს, რომ საქართველოს მოსამართლეთა კონფერენციის სისტემაში, ამ კანონის 63-ე მუხლით განსაზღვრული ფუნქციების შესრულების ხელშეწყობის მიზნით, იქმნება ადმინისტრაციული კომიტეტი.', 'საქართველოს ორგანული კანონი „საერთო სასამართლოების შესახებ“', 'მუხლი 64', '', '2026-03-04', false, 'იუსტიციის მსმენელის მომზადების სასწავლო პროგრამამ უნდა უზრუნველყოს ამ კანონის 35​1 მუხლით გათვალისწინებული კრიტერიუმების შესაბამისი თეორიული ცოდნის გაღრმავება, პრაქტიკული უნარებისა და თვისებების განვითარება.', 'მოსამართლის სამართლებრივი და სოციალური დაცვის გარანტიები განისაზღვრება საქართველოს კონსტიტუციით, ამ კანონითა და საქართველოს კანონმდებლობით.', 'საქართველოს მოსამართლეთა კონფერენციის სისტემაში, ამ კანონის 63-ე მუხლით განსაზღვრული ფუნქციების შესრულების ხელშეწყობის მიზნით, იქმნება ადმინისტრაციული კომიტეტი.', 'მოსამართლის მიმართ დისციპლინური სამართალწარმოების დაწყების მიზეზი შეიძლება იყოს:', 'C'),
